--
-- Create or alter view [SSop].[ProjectsList]
--
GO


CREATE OR ALTER VIEW [SSop].[ProjectsList]
	   --WITH SCHEMABINDING
AS
SELECT	root_hobt.ID,
		root_hobt.RowStatus,
		root_hobt.Guid,
		CASE 
			WHEN (root_hobt.ExternalReference = N'' AND root_hobt.ProjectDescription = N'') THEN CONVERT(NVARCHAR(MAX), root_hobt.Number)
			WHEN (root_Hobt.ExternalReference = N'') THEN CONVERT(NVARCHAR(MAX), root_hobt.Number) + N' - ' + root_hobt.ProjectDescription
			ELSE root_hobt.ExternalReference + N' - ' + root_hobt.ProjectDescription
		END ListLabel
FROM	SSop.Projects root_hobt
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SCrm].[Contact_MergeInfo]
--
GO



CREATE OR ALTER VIEW [SCrm].[Contact_MergeInfo]
AS
	SELECT
			c.ID,
			c.Guid,
			c.Guid AS ParentGuid,
			c.RowStatus,
			c.RowVersion,
			c.DisplayName,
			c.FirstName,
			c.Surname,
			DefaultEmail.Value  AS Email,
			DefaultPhone.Value  AS Phone,
			DefaultMobile.Value AS Mobile
	FROM
			SCrm.Contacts c
	OUTER APPLY
			(
				SELECT
						cd.Value
				FROM
						SCrm.ContactDetails cd
				JOIN
						SCrm.ContactDetailTypes cdt ON (cdt.ID = cd.ContactDetailTypeID)
				WHERE
						(cd.ContactID = c.ID)
						AND (cdt.Name = N'E-Mail')
						AND (cd.IsDefault = 1)
			) AS DefaultEmail
	OUTER APPLY
			(
				SELECT
						cd.Value
				FROM
						SCrm.ContactDetails cd
				JOIN
						SCrm.ContactDetailTypes cdt ON (cdt.ID = cd.ContactDetailTypeID)
				WHERE
						(cd.ContactID = c.ID)
						AND (cdt.Name = N'Office')
						AND (cd.IsDefault = 1)
			) AS DefaultPhone
	OUTER APPLY
			(
				SELECT
						cd.Value
				FROM
						SCrm.ContactDetails cd
				JOIN
						SCrm.ContactDetailTypes cdt ON (cdt.ID = cd.ContactDetailTypeID)
				WHERE
						(cd.ContactID = c.ID)
						AND (cdt.Name = N'Mobile')
						AND (cd.IsDefault = 1)
			) AS DefaultMobile
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

