	IF (@IsInsert = 1)
	BEGIN
		INSERT	SCore.MergeDocumentItems
			 (RowStatus, Guid, MergeDocumentId, MergeDocumentItemTypeId, BookmarkName, EntityTypeId, SubFolderPath, ImageColumns)
		VALUES
			 (
				 1,		-- RowStatus - tinyint
				 @Guid, -- Guid - uniqueidentifier
				 @MergeDocumentID,
				 @MergeDocumentItemTypeID,
				 @BookmarkName,
