--
-- Create or alter function [SCore].[GetValidationString]
--
GO
CREATE OR ALTER FUNCTION [SCore].[GetValidationString]
(
	@ValidationResults SCore.ValidationResult READONLY
)
RETURNS NVARCHAR(MAX)
AS 
BEGIN 
	DECLARE	@ResultString NVARCHAR(MAX) = N''


	SELECT	@ResultString += STUFF (
										 (
											 SELECT N', ' + CHAR(10) + CHAR(9) + COALESCE(ep.NAME, eh.ObjectName, epg.NAME) + N' : ' + vr.Message
											 FROM		@ValidationResults AS vr
											 LEFT JOIN	SCore.EntityProperties ep ON (ep.Guid = vr.TargetGuid)
											 LEFT JOIN	SCore.EntityHobts eh ON (eh.Guid = vr.TargetGuid)
											 LEFT JOIN	SCore.EntityPropertyGroups epg ON (epg.Guid = vr.TargetGuid)
											 WHERE		(vr.IsInvalid = 1)
											 FOR XML PATH ('')
										 ),
										 1,
										 1,
										 ''
										   );

	RETURN @ResultString
END
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SCore].[tvf_SystemSecurityObjects]
--
GO

CREATE OR ALTER FUNCTION [SCore].[tvf_SystemSecurityObjects]
(
	@UserId INT
)
RETURNS TABLE
AS
RETURN 
SELECT	et.ID,
		et.RowStatus,
		et.Guid,
		N'Entity' ObjectType,
		olfu.Label MainObject,
		N'' SubObject,
		CASE WHEN EXISTS (SELECT 1 FROM SCore.ObjectSecurity AS os WHERE os.ObjectGuid = et.Guid AND os.RowStatus NOT IN (0, 254)) THEN 1 ELSE 0 END AS HasRestrictions
FROM	SCore.EntityTypes et
OUTER APPLY SCore.ObjectLabelForUser(et.LanguageLabelID, @UserId) AS olfu
WHERE	(et.RowStatus NOT IN (0, 254))
	AND	(et.IsMetaData = 0)
	AND	(et.ID > 0)
UNION ALL 
SELECT	et.ID,
		et.RowStatus,
		et.Guid,
		N'Entity Property' ObjectType,
		et_olfu.Label MainObject,
		ep_olfu.Label SubObject,
		CASE WHEN EXISTS (SELECT 1 FROM SCore.ObjectSecurity AS os WHERE os.ObjectGuid = ep.Guid AND os.RowStatus NOT IN (0, 254)) THEN 1 ELSE 0 END AS HasRestrictions
FROM	SCore.EntityProperties AS ep
JOIN	SCore.EntityHobts AS eh ON (eh.ID = ep.EntityHoBTID)
JOIN	SCore.EntityTypes et ON (et.ID = eh.EntityTypeID)
OUTER APPLY SCore.ObjectLabelForUser(et.LanguageLabelID, @UserId) AS et_olfu
OUTER APPLY SCore.ObjectLabelForUser(ep.LanguageLabelID, @UserId) AS ep_olfu
WHERE	(ep.RowStatus NOT IN (0, 254))
	AND	(et.IsMetaData = 0)
	AND	(et.ID > 0)
UNION ALL 
SELECT	gvd.ID,
		gvd.RowStatus,
		gvd.Guid,
		N'Grid View',
		gv_olfu.Label MainObject,
		N'' SubObject,
		CASE WHEN EXISTS (SELECT 1 FROM SCore.ObjectSecurity AS os WHERE os.ObjectGuid = gvd.Guid AND os.RowStatus NOT IN (0, 254)) THEN 1 ELSE 0 END AS HasRestrictions
FROM	SUserInterface.GridViewDefinitions AS gvd
OUTER APPLY SCore.ObjectLabelForUser(gvd.LanguageLabelId, @UserId) AS gv_olfu
WHERE	(gvd.RowStatus NOT IN (0, 254))
	AND	(NOT EXISTS
			(
				SELECT	1
				FROM	SCore.EntityTypes AS et
				WHERE	(et.IsMetaData = 0)
					AND	(et.ID = gvd.EntityTypeID)
			)
		)
UNION ALL 
SELECT	gvcd.ID,
		gvcd.RowStatus,
		gvcd.Guid,
		N'Grid View Column',
		gv_olfu.Label MainObject,
		gvcd_olfu.Label SubObject,
		CASE WHEN EXISTS (SELECT 1 FROM SCore.ObjectSecurity AS os WHERE os.ObjectGuid = gvcd.Guid AND os.RowStatus NOT IN (0, 254)) THEN 1 ELSE 0 END AS HasRestrictions
FROM	SUserInterface.GridViewColumnDefinitions AS gvcd 
JOIN	SUserInterface.GridViewDefinitions AS gvd ON (gvd.ID = gvcd.GridViewDefinitionId)
OUTER APPLY SCore.ObjectLabelForUser(gvd.LanguageLabelId, @UserId) AS gv_olfu
OUTER APPLY SCore.ObjectLabelForUser(gvcd.LanguageLabelId, @UserId) AS gvcd_olfu
WHERE	(gvd.RowStatus NOT IN (0, 254))
	AND	(NOT EXISTS
			(
				SELECT	1
				FROM	SCore.EntityTypes AS et
				WHERE	(et.IsMetaData = 0)
					AND	(et.ID = gvd.EntityTypeID)
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SCore].[tvf_PropertiesForEntityType]
--
GO
CREATE OR ALTER FUNCTION [SCore].[tvf_PropertiesForEntityType]
	(
		@Guid UNIQUEIDENTIFIER,
		@UserId INT
	)
RETURNS TABLE
	   --WITH SCHEMABINDING 
AS
RETURN SELECT		p.RowStatus,
					p.RowVersion,
					p.Guid,
					p.Name,
					e.Guid	  AS EntityTypeGuid,
					ll.Guid	  AS LanguageLabelGuid,
					edt.Guid  AS EntityDataTypeGuid,
					p.IsReadOnly,
					p.IsImmutable,
					p.IsHidden,
					p.IsCompulsory,
					p.MaxLength,
					p.Precision,
					p.Scale,
					p.DoNotTrackChanges,
					epg.Guid  AS EntityPropertyGroupGuid,
					p.SortOrder,
					p.GroupSortOrder,
					ISNULL (   os.CanRead,
							   0
						   )  AS CanRead,
					ISNULL (   os.CanWrite,
							   0
						   )  AS CanWrite,
					edt.Name  AS EntityDataTypeName,
					ISNULL (   lt.Label,
							   p.Name
						   )  AS Label,
					ddld.Guid AS DropDownListDefinitionGuid,
					ddld.DetailPageUrl,
					ddld.InformationPageUrl,
					ddld.IsDetailWindowed,
					ddlde.Guid AS ForeignEntityTypeGuid,
					p.IsObjectLabel,
					p.IsParentRelationship,
					hobt.Guid AS EntityHoBTGuid,
					p.IsLongitude,
					p.IsLatitude,
					p.IsUppercase,
					p.IsIncludedInformation,
					p.FixedDefaultValue,
					p.SqlDefaultValueStatement,
					p.AllowBulkChange,
					p.IsVirtual
	   FROM			SCore.EntityProperties					AS p
	   JOIN			SCore.EntityDataTypes					AS edt ON (p.EntityDataTypeID = edt.ID)
	   JOIN			SCore.EntityHobts						AS hobt ON (p.EntityHoBTID = hobt.ID)
	   JOIN			SCore.EntityTypes						AS e ON (hobt.EntityTypeID = e.ID)
	   JOIN			SCore.EntityPropertyGroups				AS epg ON (p.EntityPropertyGroupID = epg.ID)
	   JOIN			SUserInterface.DropDownListDefinitions AS ddld ON (ddld.ID = p.DropDownListDefinitionID)
	   JOIN			SCore.EntityTypes						AS ddlde ON (ddlde.ID = ddld.EntityTypeId)
	   JOIN			SCore.LanguageLabels					AS ll ON (ll.ID = p.LanguageLabelID)
	   OUTER APPLY	SCore.ObjectSecurityForUser (	p.Guid,
													@UserId
												)			AS os
	   OUTER APPLY	SCore.ObjectLabelForUser (	 p.LanguageLabelID,
												 @UserId
											 ) AS lt
	   WHERE		(e.Guid = @Guid)
				AND	(p.RowStatus NOT IN (0, 254))

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SCore].[RebuildRecordHistoryTriggers]
--
GO



CREATE OR ALTER PROCEDURE [SCore].[RebuildRecordHistoryTriggers]
AS
BEGIN
	SET NOCOUNT ON;

	DECLARE	@MaxTableID BIGINT,
			@CurrentTableID BIGINT,
			@stmt NVARCHAR(MAX),
			@SchemaName NVARCHAR(250),
			@TableName NVARCHAR(250),
			@MaxColumnID BIGINT,
			@CurrentColumnID BIGINT,
			@ColumnName NVARCHAR(250),
			@PrimaryKeyColumn NVARCHAR(254),
			@HobtId INT,
			@EntityPropertyId INT,
			@IsMainTable BIT,
			@EntityTypeId INT,
			@MainHobtSchema NVARCHAR(250),
			@MainHobtName NVARCHAR(250)

	DECLARE	@HoBTs TABLE 
	(
		ID BIGINT IDENTITY(1,1) PRIMARY KEY,
		SchemaName NVARCHAR(250),
		TableName NVARCHAR(250),
		PrimaryKeyColumn NVARCHAR(254),
		HobtId INT,
		EntityTypeId INT,
		IsMainTable BIT
	)

	DECLARE	@Columns TABLE 
	(
		ID BIGINT IDENTITY(1,1) PRIMARY KEY,
		ColumnName NVARCHAR(250),
		EntityPropertyId INT
	)

	INSERT @HoBTs
		 (SchemaName, TableName, PrimaryKeyColumn, HobtID, EntityTypeID, IsMainTable)
	SELECT	h.SchemaName, h.ObjectName, N'ID', h.ID, h.EntityTypeID, h.IsMainHoBT
	FROM	SCore.EntityHobts h
	JOIN	SCore.EntityTypes et ON (et.ID = h.EntityTypeID)
	WHERE	(et.DoNotTrackChanges = 0)
		AND	(h.RowStatus NOT IN (0, 254))
		AND	(et.RowStatus NOT IN (0, 254))
		AND (h.ObjectType = N'U')
		AND (et.Id > 0)

	SELECT	@MaxTableID = MAX(ID),
			@CurrentTableID = 0
	FROM	@HoBTs

	-- Rebuild Record History Triggers
	WHILE (@CurrentTableID < @MaxTableID)
	BEGIN 
		SELECT	TOP(1) @CurrentTableID = ID,
				@SchemaName = SchemaName,
				@TableName = TableName,
				@PrimaryKeyColumn = PrimaryKeyColumn,
				@HobtId = HobtId,
				@IsMainTable = IsMainTable,
				@EntityTypeId = EntityTypeId
		FROM	@HoBTs
		WHERE	(ID > @CurrentTableID)
		ORDER BY ID

		PRINT @TableName

        -- Get a collection of all the columns in the table. 
        DELETE @Columns
		INSERT	@Columns
			(
				ColumnName,
				EntityPropertyId
			)
		SELECT	ep.name, ep.Id
		FROM	SCore.EntityProperties ep
		JOIN	SCore.EntityDataTypes edt ON (edt.ID = ep.EntityDataTypeID)
		WHERE	(ep.EntityHoBTID = @HobtId)
			AND	(ep.RowStatus NOT IN (0, 254))
			AND	(ep.IsVirtual = 0)
			AND	(ep.DoNotTrackChanges = 0)
			AND	(ep.name NOT IN (N'RowVersion'))

        -- Drop the trigger if it alread exists 
		IF (EXISTS (SELECT 1 FROM sys.triggers WHERE (name = N'tg_' + @TableName + N'_RecordHistory')))
		BEGIN 
			SET @stmt = N'DROP TRIGGER ' + @SchemaName + N'.[tg_' + @TableName +  N'_RecordHistory]'			

			EXEC sp_executesql @stmt
		END

		SET @stmt = N'CREATE TRIGGER '+ @SchemaName + N'.[tg_' + @TableName + N'_RecordHistory]
   ON  ' + @SchemaName + N'.[' + @TableName + N']	
   AFTER INSERT, UPDATE
AS 
BEGIN
	SET NOCOUNT ON;

    IF (ISNULL(CONVERT(int, SESSION_CONTEXT(N''S_disable_triggers'')), 0) = 1)
    BEGIN 
        RETURN
    END

	IF (EXISTS
			(
				SELECT	1
				FROM	Inserted
				WHERE	(ID = -1) 
			)
		)
	BEGIN 
		;THROW 60000, N''Data integrity exception: Attempt to alter -1 record'', 1
	END

    DECLARE	@PreviousValue NVARCHAR(MAX),
			@NewValue NVARCHAR(MAX),
			@UserID INT = 0,
			@SchemaName NVARCHAR(250) = N''' + @SchemaName + ''',
			@TableName NVARCHAR(250) = N''' + @TableName + ''',
			@ColumnName NVARCHAR(250),
			@MaxInsertedID BIGINT,
			@CurrentInsertedID BIGINT,
			@CurrentInsertedGuid UNIQUEIDENTIFIER

	SELECT @UserID = ISNULL(CONVERT(int, SESSION_CONTEXT(N''user_id'')), -1)

	SELECT	@MaxInsertedID = MAX([' + @PrimaryKeyColumn + ']),
			@CurrentInsertedID = -1
	FROM	Inserted

	WHILE	(@CurrentInsertedID < @MaxInsertedID)
	BEGIN '

	IF (@IsMainTable = 1)  
	BEGIN 

		SET @stmt = @stmt + N'
		SELECT	TOP(1) @CurrentInsertedID = i.[' + @PrimaryKeyColumn + '],
				@CurrentInsertedGuid = i.Guid
		FROM	Inserted i
		WHERE	(i.[' + @PrimaryKeyColumn + '] > @CurrentInsertedID)
			ORDER BY i.[' + @PrimaryKeyColumn + ']
		
		'
	END 
	ELSE
	BEGIN 
		SELECT	@MainHobtSchema = h.SchemaName,
				@MainHobtName = h.ObjectName
		FROM	SCore.EntityHobts h
		WHERE	(h.IsMainHoBT = 1)
			AND	(h.EntityTypeID = @EntityTypeId)
			AND	(h.RowStatus NOT IN (0, 254))


		SET @stmt = @stmt + N'
		SELECT	TOP(1) @CurrentInsertedID = i.[' + @PrimaryKeyColumn + ']
		FROM	Inserted i
		WHERE	(i.[' + @PrimaryKeyColumn + '] > @CurrentInsertedID)
			ORDER BY i.[' + @PrimaryKeyColumn + ']

		SELECT	TOP(1) @CurrentInsertedGuid = i.Guid
		FROM	[' + @MainHobtSchema + '].[' + @MainHobtName + '] i
		WHERE	(ID =  @CurrentInsertedID)
		
		'
	END

		IF (EXISTS (SELECT 1 FROM @Columns WHERE (ColumnName = N'last_updated_by')))
        BEGIN 
            SET @stmt = @stmt + N'-- Get the user from last_updated_by if it wasn''t in the session
            IF (@UserID <= 0)
            BEGIN 
                SELECT  @UserID = ISNULL(i.last_updated_by, -1)
                FROM    Inserted i
                WHERE	(i.[' + @PrimaryKeyColumn + '] = @CurrentInsertedID)   
            END
            
            '
        END

		SET @stmt = @stmt + N'
		
		IF (NOT EXISTS 
				(
					SELECT	1
					FROM 	deleted d
					WHERE	(d.[' + @PrimaryKeyColumn + '] = @CurrentInsertedID)
				)
			)
		BEGIN 
				
				INSERT	SCore.RecordHistory
				(
					RowStatus, SchemaName, TableName, ColumnName, RowID, RowGuid, UserID, PreviousValue, NewValue, SQLUser, EntityPropertyID
				)
				VALUES(1, @SchemaName, @TableName, N'''', @CurrentInsertedID, @CurrentInsertedGuid, @UserID, N'''', N'''', SYSTEM_USER, -1)
	
			RETURN 
		END
		
		'

		SELECT	@MaxColumnID = MAX(ID),
				@CurrentColumnID = 0
		FROM	@Columns
			
		WHILE (@CurrentColumnID < @MaxColumnID)
		BEGIN 
			SELECT	TOP(1) @CurrentColumnID = ID,
					@ColumnName = ColumnName,
					@EntityPropertyId = EntityPropertyId
			FROM	@Columns 
			WHERE	(id > @CurrentColumnID)
			ORDER BY ID

			SET @stmt = @stmt +
			N'SELECT	
					@PreviousValue = ISNULL(CONVERT(NVARCHAR(max), d.[' + @ColumnName + ']), N''''),
					@NewValue = ISNULL(CONVERT(NVARCHAR(max), i.[' + @ColumnName + ']), N'''')
			FROM	Inserted i
			JOIN	Deleted d ON (i.[' + @PrimaryKeyColumn + '] = d.[' + @PrimaryKeyColumn + '])
			WHERE	(i.[' + @PrimaryKeyColumn + '] = @CurrentInsertedID)
                AND (d.[' + @ColumnName + '] IS DISTINCT FROM i.[' + @ColumnName + '])


			IF (@@RowCount > 0)
			BEGIN 
				INSERT	SCore.RecordHistory
				(
					RowStatus, SchemaName, TableName, ColumnName, RowID, RowGuid, UserID, PreviousValue, NewValue, SQLUser, EntityPropertyID
				)
				VALUES(1, @SchemaName, @TableName, N''' + @ColumnName + N''', @CurrentInsertedID, @CurrentInsertedGuid, @UserID, @PreviousValue, @NewValue, SYSTEM_USER, ' + CONVERT(NVARCHAR(MAX), @EntityPropertyId) + ')
			END 
			
			'

		END

		 SET @stmt = @stmt + N'
			END
		END
		
		'

		--PRINT @stmt

		EXECUTE sp_executesql @stmt
	END
	
END
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SCore].[PostDeploymentScript]
--
GO
CREATE OR ALTER PROCEDURE [SCore].[PostDeploymentScript]
AS 
BEGIN 
	SET NOCOUNT ON 

	-- Ensure no missing Guid records. 
	PRINT 'Add missing Data Object rows'
	DECLARE @MaxEntityType INT,
		@CurrentEntityType INT = 0,
		@TableName NVARCHAR(500),
		@stmt NVARCHAR(MAX)

	SELECT @MaxEntityType = MAX (ID)
	FROM	SCore.EntityTypes et 
	where	(RowStatus = 1)
		AND	(EXISTS
				(
					SELECT	1
					FROM	SCore.EntityHobts AS eh
					WHERE	(eh.EntityTypeID = et.ID)
						AND	(eh.ObjectType = 'U')
						AND	(eh.RowStatus NOT IN (0, 254))
				)
			)

	WHILE	(@CurrentEntityType < @MaxEntityType)
	BEGIN 
		SELECT	TOP(1) @TableName = h.SchemaName + N'.' + h.ObjectName,
				@CurrentEntityType = et.ID
		FROM	SCore.EntityTypes et 
		JOIN	SCore.EntityHobts h ON (h.EntityTypeID = et.ID)
		WHERE	(h.IsMainHoBT = 1)
			AND	(h.ObjectType = 'U')
			AND	(et.ID > @CurrentEntityType)
			AND	(et.RowStatus = 1)
		ORDER BY	et.ID

		PRINT @TableName

		SET @stmt = N'INSERT	SCore.DataObjects
		 (Guid, RowStatus, EntityTypeId)
	SELECT	t1.Guid, t1.RowStatus, ' + CONVERT(NVARCHAR(MAX), @CurrentEntityType) + N'
	FROM	' + @TableName + ' t1
	WHERE	(Guid <> ''00000000-0000-0000-0000-000000000000'')
		AND	(NOT EXISTS 
				(
					SELECT 1
					FROM	SCore.DataObjects do 
					WHERE	(do.Guid = t1.Guid)
				)
			)'



		EXEC sp_executesql @stmt
	END

  DECLARE @Maxid     INT,
          @CurrentId INT;

  DECLARE @ForeignKeyStatements TABLE
      (
        id        INT            NOT NULL IDENTITY (1, 1),
        statement NVARCHAR(4000) NOT NULL DEFAULT ''
      )


PRINT N'Enable Data Object Key Contraints'
  INSERT @ForeignKeyStatements
        (
          statement
        )
      SELECT
              --N'ALTER TABLE [' + SCHEMA_NAME(po.schema_id) + N'].[' + po.Name + N'] NOCHECK CONSTRAINT [' + fk.Name + ']'
              N'ALTER TABLE [' + SCHEMA_NAME(po.schema_id) + N'].[' + po.name + N'] CHECK CONSTRAINT [' + fk.name + ']'
      FROM
              sys.foreign_keys fk
      JOIN
              sys.objects po ON (fk.parent_object_id = po.object_id)
      JOIN
              sys.objects ro ON (fk.referenced_object_id = ro.object_id)
      WHERE
              (ro.Name = N'DataObjects');


  SELECT
          @MaxId     = MAX(ID),
          @CurrentId = -1
  FROM
          @ForeignKeyStatements

  WHILE (@CurrentId < @Maxid)
  BEGIN
    SELECT TOP (1)
            @CurrentID = ID,
            @stmt      = statement
    FROM
            @ForeignKeyStatements
    WHERE
            (ID > @CurrentId)
    ORDER BY
            ID

	PRINT @stmt

    EXEC sys.sp_executesql
      @stmt;
  END

	-- Rebuild History Triggers
	PRINT N'Rebuild triggers'
	EXEC SCore.RebuildRecordHistoryTriggers

	-- Enable Schema Binding 
	PRINT 'Enable Schema Binding'
	EXEC SCore.SCHEMABINDING @Apply = 1	-- bit

	-- Check for missing -1 records
	PRINT 'Add missing default rows'
	EXEC SCore.CreateDefaultRows
	

END
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SCore].[EntityPropertyUpsert]
--
GO
CREATE OR ALTER PROCEDURE [SCore].[EntityPropertyUpsert]
	(	@Name NVARCHAR(250),
		@RowStatus TINYINT,
		@LanguageLabelGuid UNIQUEIDENTIFIER,
		@EntityHobtGuid UNIQUEIDENTIFIER,
		@EntityDataTypeGuid UNIQUEIDENTIFIER,
		@IsReadOnly BIT,
		@IsImmutable BIT,
		@IsUppercase BIT,
		@IsHidden BIT,
		@IsCompulsory BIT,
		@MaxLength INT,
		@Precision INT,
		@Scale INT,
		@DoNotTrackChanges BIT,
		@EntityPropertyGroupGuid UNIQUEIDENTIFIER,
		@SortOrder SMALLINT,
		@GroupSortOrder SMALLINT,
		@IsObjectLabel BIT,
		@DropDownListDefinitionGuid UNIQUEIDENTIFIER,
		@IsParentRelationship BIT,
		@IsIncludedInformation BIT,
		@IsLatitude BIT,
		@IsLongitude BIT,
		@FixDefaultValue NVARCHAR(50),
		@SqlDefaultValueStatement NVARCHAR(4000),
		@AllowBulkChange BIT,
		@IsVirtual BIT,
		@Guid UNIQUEIDENTIFIER OUT
	)
AS
BEGIN
	SET NOCOUNT ON 

	DECLARE @LanguageLabelID		  INT,
			@EntityHobtID			  INT,
			@EntityDateTypeID		  INT,
			@EntityPropertyGroupID	  INT,
			@DropDownListDefinitionID INT;

	IF (@LanguageLabelGuid = '00000000-0000-0000-0000-000000000000')
	BEGIN
		SET @LanguageLabelGuid = NEWID ();
	END;

	-- If the language label isn't set, create one based on the name. 
	SELECT	@LanguageLabelID = ID
	FROM	SCore.LanguageLabels
	WHERE	(Guid = @LanguageLabelGuid);

	IF (@LanguageLabelID = -1)
	BEGIN
		EXECUTE SCore.LanguageLabelUpsert @Name = @Name,
										  @Guid = @LanguageLabelGuid OUT;

		SELECT	@LanguageLabelID = ID
		FROM	SCore.LanguageLabels
		WHERE	(Guid = @LanguageLabelGuid);
	END;

	SELECT	@EntityDateTypeID = ID
	FROM	SCore.EntityDataTypes
	WHERE	(Guid = @EntityDataTypeGuid);

	SELECT	@EntityHobtID = ID
	FROM	SCore.EntityHobts
	WHERE	(Guid = @EntityHobtGuid);

	SELECT	@EntityPropertyGroupID = ID
	FROM	SCore.EntityPropertyGroups
	WHERE	(Guid = @EntityPropertyGroupGuid);

	SELECT	@DropDownListDefinitionID = ID
	FROM	SUserInterface.DropDownListDefinitions
	WHERE	(Guid = @DropDownListDefinitionGuid);

	DECLARE @IsInsert BIT = 0;
	EXEC SCore.UpsertDataObject @Guid = @Guid,					-- uniqueidentifier
								@SchemeName = N'SCore',			-- nvarchar(255)
								@ObjectName = N'EntityProperties',		-- nvarchar(255)
								@IsInsert = @IsInsert OUTPUT;	-- bit

	IF (@IsInsert = 1)
	BEGIN
		INSERT	SCore.EntityProperties
			 (Guid,
			  Name,
			  RowStatus,
			  LanguageLabelID,
			  EntityHoBTID,
			  EntityDataTypeID,
			  IsReadOnly,
			  IsImmutable,
			  IsUppercase,
			  IsHidden,
			  IsCompulsory,
			  MaxLength,
			  Precision,
			  Scale,
			  DoNotTrackChanges,
			  EntityPropertyGroupID,
			  SortOrder,
			  GroupSortOrder,
			  IsObjectLabel,
			  DropDownListDefinitionID,
			  IsParentRelationship,
			  IsIncludedInformation,
			  IsLatitude,
			  IsLongitude,
			  FixedDefaultValue,
			  SqlDefaultValueStatement,
			  AllowBulkChange,
			  IsVirtual)
		VALUES
			 (
				 @Guid,
				 @Name,
				 1,
				 @LanguageLabelID,
				 @EntityHobtID,
				 @EntityDateTypeID,
				 @IsReadOnly,
				 @IsImmutable,
				 @IsUppercase,
				 @IsHidden,
				 @IsCompulsory,
				 @MaxLength,
				 @Precision,
				 @Scale,
				 @DoNotTrackChanges,
				 @EntityPropertyGroupID,
				 @SortOrder,
				 @GroupSortOrder,
				 @IsObjectLabel,
				 @DropDownListDefinitionID,
				 @IsParentRelationship,
				 @IsIncludedInformation,
				 @IsLatitude,
				 @IsLongitude,
				 @FixDefaultValue,
				 @SqlDefaultValueStatement,
				 @AllowBulkChange,
				 @IsVirtual
			 );
	END;
	ELSE
	BEGIN
		UPDATE	SCore.EntityProperties
		SET		Name = @Name,
				RowStatus = @RowStatus,
				LanguageLabelID = @LanguageLabelID,
				EntityHoBTID = @EntityHobtID,
				EntityDataTypeID = @EntityDateTypeID,
				IsReadOnly = @IsReadOnly,
				IsImmutable = @IsImmutable,
				IsUppercase = @IsUppercase,
				IsHidden = @IsHidden,
				IsCompulsory = @IsCompulsory,
				MaxLength = @MaxLength,
				Precision = @Precision,
				Scale = @Scale,
				DoNotTrackChanges = @DoNotTrackChanges,
				EntityPropertyGroupID = @EntityPropertyGroupID,
				SortOrder = @SortOrder,
				GroupSortOrder = @GroupSortOrder,
				IsObjectLabel = @IsObjectLabel,
				DropDownListDefinitionID = @DropDownListDefinitionID,
				IsParentRelationship = @IsParentRelationship,
				IsIncludedInformation = @IsIncludedInformation,
				IsLongitude = @IsLongitude,
				IsLatitude = @IsLatitude,
				FixedDefaultValue = @FixDefaultValue,
				SqlDefaultValueStatement = @SqlDefaultValueStatement,
				AllowBulkChange = @AllowBulkChange,
				IsVirtual = @IsVirtual
		WHERE	(Guid = @Guid);
	END;


END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SCore].[EntityPropertiesV]
