		INSERT SCrm.AccountAddresses
			 (RowStatus, Guid, AccountID, AddressID)
		VALUES
			 (
				 1,	-- RowStatus - tinyint
				 @Guid,	-- Guid - uniqueidentifier
				 @AccountID,	-- AccountID - int
				 @AddressID	-- AddressID - int
			 )
    END
    ELSE
    BEGIN 
        UPDATE  SCrm.AccountAddresses
        SET     AccountID = @AccountID,
				AddressID = @AddressID
