--
CREATE INDEX [Quotes_Number]
  ON [SSop].[Quotes] ([Number] DESC, [RevisionNumber], [RowStatus])
  WHERE ([RowStatus]<>(0) AND [RowStatus]<>(254))
  WITH (FILLFACTOR = 80)
  ON [PRIMARY]
