				)
				VALUES(1, @SchemaName, @TableName, N'DeadDate', @CurrentInsertedID, @CurrentInsertedGuid, @UserID, @PreviousValue, @NewValue, SYSTEM_USER, 1694)
			END 
			
			
			END
		END
		
		
