--
-- Create or alter function [SSop].[tvf_ScheduleOfClientInformation]
--
GO






CREATE OR ALTER FUNCTION [SSop].[tvf_ScheduleOfClientInformation]
(
	@UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
             --WITH SCHEMABINDING
AS RETURN	
SELECT  soci.ID,
        soci.RowStatus,
        soci.RowVersion,
        soci.Guid,
		soci.Item
FROM    SSop.ScheduleOfClientInformation AS soci

WHERE   (soci.RowStatus NOT IN (0, 254))
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(soci.Guid, @UserId) oscr
			)
		)
	AND	(EXISTS 
			(
				SELECT	1
				FROM	SSop.Enquiries AS e
				WHERE	(e.Guid = @ParentGuid)
					AND	(e.ID = soci.EnquiryId)
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SSop].[ScheduleOfClientInformationUpsert]
--
GO









CREATE OR ALTER PROCEDURE [SSop].[ScheduleOfClientInformationUpsert]
  (
    @EnquiryGuid        UNIQUEIDENTIFIER,
    @Item				NVARCHAR(200),
    @Guid               UNIQUEIDENTIFIER
  )
AS
  BEGIN
    DECLARE @EnquiryId        INT = -1,
            @IsInsert         BIT;

    SELECT
            @EnquiryId = ID
    FROM
            SSop.Enquiries
    WHERE
            (Guid = @EnquiryGuid);


    EXEC SCore.UpsertDataObject
      @Guid       = @Guid,					-- uniqueidentifier
      @SchemeName = N'SSop',				-- nvarchar(255)
      @ObjectName = N'EnquiryServices',				-- nvarchar(255)
	  @IncludeDefaultSecurity = 0,
      @IsInsert   = @IsInsert OUTPUT;	-- bit

    IF (@IsInsert = 1)
      BEGIN
        INSERT SSop.ScheduleOfClientInformation
              (
                RowStatus,
                Guid,
                EnquiryId,
                Item
              )
        VALUES
                (
                  1,	-- RowStatus - tinyint
                  @Guid,	-- Guid - uniqueidentifier
                  @EnquiryId,	-- EnquiryId - int
                  @Item
                )
      END;
    ELSE
      BEGIN
        UPDATE  SSop.ScheduleOfClientInformation
        SET     EnquiryId = @EnquiryId,
                Item = @Item
        WHERE
          (Guid = @Guid);
      END;

  END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

