--
-- Create or alter view [SJob].[JobStatus]
--
GO







CREATE OR ALTER VIEW [SJob].[JobStatus]
   --WITH SCHEMABINDING
AS 
SELECT	j.ID,
		CASE 
			WHEN (j.JobCompleted IS NOT NULL) THEN N'Completed'
			WHEN (j.JobCancelled IS NOT NULL) THEN N'Cancelled'
			WHEN (j.DeadDate IS NOT NULL) THEN N'Dead'
			WHEN (j.JobDormant IS NOT NULL) THEN N'Dormant'
			WHEN (j.ReviewedDateTimeUTC IS NOT NULL) THEN N'Reviewed'
			WHEN (j.IsCompleteForReview = 1) THEN N'Complete for Review'
			WHEN ((j.JobStarted IS NOT NULL) AND (j.JobCompleted IS NULL) AND (j.JobCancelled IS NULL) AND (j.JobDormant IS NULL) AND (j.IsCompleteForReview = 0) AND (j.ReviewedDateTimeUTC IS NULL) AND (j.DeadDate IS NULL)) THEN N'Live'
			WHEN (j.JobStarted IS NULL) THEN N'Not Started'
			ELSE N'Unknown'
		END AS JobStatus,
		p.IsSubjectToNDA
FROM	SJob.Jobs j
JOIN	SSop.Projects AS p ON (p.ID = j.ProjectId)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_Jobs_TeamNoFormalAppointment]
--
GO

CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_TeamNoFormalAppointment]
	(
		@UserId INT
	)
RETURNS TABLE
         --WITH SCHEMABINDING
AS
RETURN	SELECT		j.ID,
					j.RowStatus,
					j.RowVersion,
					j.Guid,
					j.Number,
					j.JobDescription,
					j.JobTypeID,
					client.Name AS  Client,
					jt.Name	   AS JobTypeName,
					i.Guid	   AS SurveyorGuid,
					i.FullName AS SurveyorName,
					j.JobStarted AS DueDateTimeUTC,
					js.IsSubjectToNDA
	   FROM			SJob.Jobs					  AS j
	   JOIN			SJob.JobStatus AS js ON (js.ID = j.ID)
	   JOIN			SJob.JobTypes				  AS jt ON (j.JobTypeID = jt.ID)
	   JOIN			SCore.Identities			  AS i ON (j.SurveyorID = i.ID)
	   JOIN			SCrm.Accounts client ON (client.ID = j.ClientAccountID)
	   CROSS APPLY	(
						SELECT	ou1.OrgNode
						FROM	SCore.OrganisationalUnits ou1
						JOIN	SCore.Identities i1 ON (i1.OriganisationalUnitId = ou1.ID)
						WHERE	(i1.Id = @UserId)
					) CurrentUser
	   WHERE		(j.RowStatus NOT IN (0, 254))
				AND	(EXISTS
			(
					SELECT
							1
					FROM
							SCore.ObjectSecurityForUser_CanRead(j.Guid, @UserId) oscr
			)
		)
				AND	(j.IsActive = 1)
				AND (j.IsPendingCompletion = 0)
				AND	(j.ClientAppointmentReceived = 0)
				AND (EXISTS
						(
							SELECT	1
							FROM	SCore.OrganisationalUnits ou2
							WHERE	(ou2.ID = i.OriganisationalUnitId)
								AND (ou2.OrgNode.IsDescendantOf(CurrentUser.OrgNode) = 1)
						)
					)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_Jobs_TeamDormant]
--
GO




CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_TeamDormant]
	(
		@UserId INT
	)
RETURNS TABLE
   --WITH SCHEMABINDING
AS
RETURN SELECT	j.ID,
				j.RowStatus,
				j.RowVersion,
				j.Guid,
				j.Number,
				j.JobDescription,
				j.JobTypeID,
				jt.Name							  AS JobTypeName,
				i.Guid							  AS SurveyorGuid,
				client.Name + N' / ' + agent.Name AS ClientAgent,
				i.FullName						  AS SurveyorName,
				prop.FormattedAddressComma,
				js.IsSubjectToNDA,
				j.IsComplete,
				js.JobStatus,
				j.JobDormant
	   FROM		SJob.Jobs		 AS j
	   JOIN		SJob.JobStatus	 AS js ON (js.ID = j.ID)
	   JOIN		SJob.JobTypes	 AS jt ON (j.JobTypeID = jt.ID)
	   JOIN		SCore.Identities AS i ON (j.SurveyorID = i.ID)
	   JOIN		SJob.Properties	 AS prop ON (prop.ID = j.UprnID)
	   JOIN		SCrm.Accounts	 AS client ON (client.ID = j.ClientAccountID)
	   JOIN		SCrm.Accounts	 AS agent ON (agent.ID = j.AgentAccountID)
	   CROSS APPLY
				(
					SELECT	ou1.OrgNode
					FROM	SCore.OrganisationalUnits AS ou1
					JOIN	SCore.Identities		  AS i1 ON (i1.OriganisationalUnitId = ou1.ID)
					WHERE	(i1.ID = @UserId)
				)				 AS CurrentUser
	   WHERE	(j.RowStatus NOT IN (0, 254))
			AND (j.ID		   > 0)
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.ObjectSecurityForUser_CanRead (	j.Guid,
																@UserId
															) AS oscr
		   )
				)
			AND (j.IsComplete = 0)
			AND (j.JobDormant IS NOT NULL)
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.OrganisationalUnits AS ou2
			   WHERE	(ou2.ID											  = i.OriganisationalUnitId)
					AND (ou2.OrgNode.IsDescendantOf (CurrentUser.OrgNode) = 1)
		   )
				);
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_Jobs_TeamCompleteForReview]
--
GO


CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_TeamCompleteForReview]
	(
		@UserId INT
	)
RETURNS TABLE
     --WITH SCHEMABINDING
AS
RETURN SELECT	j.ID,
				j.RowStatus,
				j.RowVersion,
				j.Guid,
				j.Number,
				j.JobDescription,
				j.JobTypeID,
				client.Name AS Client,
				jt.Name		AS JobTypeName,
				i.Guid		AS SurveyorGuid,
				i.FullName	AS SurveyorName,
				js.IsSubjectToNDA
	   FROM		SJob.Jobs		 AS j
	   JOIN		SJob.JobStatus AS js ON (js.ID = j.ID)
	   JOIN		SJob.JobTypes	 AS jt ON (j.JobTypeID	 = jt.ID)
	   JOIN		SCore.Identities AS i ON (j.SurveyorID	 = i.ID)
	   JOIN		SCrm.Accounts	 AS client ON (client.ID = j.ClientAccountID)
	   CROSS APPLY
					(
						SELECT	ou1.OrgNode
						FROM	SCore.OrganisationalUnits AS ou1
						JOIN	SCore.Identities		  AS i1 ON (i1.OriganisationalUnitId = ou1.ID)
						WHERE	(i1.ID = @UserId)
					) AS CurrentUser
	   WHERE	(j.RowStatus NOT IN (0, 254))
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.ObjectSecurityForUser_CanRead (	j.Guid,
																@UserId
															) AS oscr
		   )
				)
			AND (j.IsComplete		   = 0)
			AND (j.IsCompleteForReview = 1)
			AND (j.ReviewedByUserID	   < 0)
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.OrganisationalUnits AS ou2
			   WHERE	(ou2.ID											  = i.OriganisationalUnitId)
					AND (
							(ou2.OrgNode.IsDescendantOf (CurrentUser.OrgNode) = 1)
						OR	(ou2.OrgNode = CurrentUser.OrgNode)
						)

		   )
					)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

