--
GO



CREATE OR ALTER FUNCTION [SSop].[tvf_Quotes_CreatedJobs] 
(
	@ParentGuid UNIQUEIDENTIFIER,
    @UserId INT
)
RETURNS TABLE
             --WITH SCHEMABINDING
AS
RETURN 
SELECT  j.ID,
        j.RowStatus,
        j.RowVersion,
        j.Guid,
        j.Number,
        j.JobDescription,
        j.JobTypeID,
        jt.Name AS JobTypeName,
		i.Guid SurveyorGuid,
		i.FullName AS SurveyorName, 
		j.IsComplete,
		js.JobStatus
FROM    SJob.Jobs j
JOIN	SJob.JobStatus js ON (js.ID = j.ID)
JOIN    SJob.JobTypes jt ON (j.JobTypeID = jt.ID)
JOIN    SCore.Identities i ON (j.SurveyorID = i.ID)
WHERE   (j.RowStatus  NOT IN (0, 254))
	AND	(j.Id > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(j.Guid, @UserId) oscr
			)
		)
	AND	(EXISTS 
			(
				SELECT	1
				FROM	SSop.QuoteItems qi
				JOIN	SSop.Quotes q ON (q.ID = qi.QuoteId)
				WHERE	(q.Guid = @ParentGuid)
					AND	(qi.CreatedJobId = j.ID) 
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_QuoteItemsValidate]
--
GO


CREATE OR ALTER FUNCTION [SSop].[tvf_QuoteItemsValidate]
	(
		@CreatedJobGuid UNIQUEIDENTIFIER,
		@Guid UNIQUEIDENTIFIER
	)
RETURNS @ValidationResult TABLE
	(
		ID INT IDENTITY(1, 1) NOT NULL,
		TargetGuid UNIQUEIDENTIFIER NOT NULL DEFAULT ('00000000-0000-0000-0000-000000000000'),
		TargetType CHAR(1) NOT NULL DEFAULT (''),
		IsReadOnly BIT NOT NULL DEFAULT ((0)),
		IsHidden BIT NOT NULL DEFAULT ((0)),
		IsInvalid BIT NOT NULL DEFAULT ((0)),
		[IsInformationOnly] [BIT] NOT NULL DEFAULT((0)),
		Message NVARCHAR(2000) NOT NULL DEFAULT ('')
	)
AS
BEGIN
    IF (EXISTS 
			(
				SELECT	1
				FROM	SSop.QuoteItems qi 
				JOIN	SSop.Quotes q ON (q.ID = qi.QuoteId)
				WHERE	(qi.CreatedJobId > 0)
					AND	(qi.Guid = @Guid)
					AND	((q.IsFinal = 1)
					OR	(q.DateSent IS NOT NULL))
			)	
	)
    BEGIN 
        DECLARE @EntityTypeGuid UNIQUEIDENTIFIER = '6474b796-c20d-4947-9406-ae1b6dffef32'

        INSERT @ValidationResult (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, [Message])
        VALUES (@EntityTypeGuid, N'E', 1, 0, 0, N'')
    END

	IF (@CreatedJobGuid = '00000000-0000-0000-0000-000000000000')
			BEGIN

				INSERT @ValidationResult
						(
							TargetGuid,
							TargetType,
							IsReadOnly,
							IsHidden,
							IsInvalid,
							[Message]
						)
				SELECT
							epfvv.Guid,
							N'P',
							1,
							1,
							0,
							N''
				FROM	SCore.EntityPropertiesForValidationV AS epfvv
				WHERE	([epfvv].[Schema] = N'SSop')
					AND	(epfvv.Hobt = N'QuoteItems')
					AND	(Name = (N'CreatedJobId'))
								
			
			END

	RETURN;
END;

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SSop].[QuotesRevise]
--
GO





CREATE OR ALTER PROCEDURE [SSop].[QuotesRevise]
	@SourceGuid UNIQUEIDENTIFIER,
	@TargetGuid UNIQUEIDENTIFIER
AS
	BEGIN

		DECLARE @SourceID INT,
				@ID		  INT,
				@IsInsert BIT;

		SELECT
				@SourceID = ID
		FROM
				SSop.Quotes
		WHERE
				(Guid = @SourceGuid);

		IF (@@ROWCOUNT > 1)
		BEGIN
			;
			THROW 60000, N'Invalid source Quote', 1;
		END;

		IF (EXISTS 
				(
					SELECT	1
					FROM	SSop.Quotes AS q 
					WHERE	(q.Guid = @SourceGuid)
						AND	(q.DateAccepted IS NOT NULL)
				)
			)
		BEGIN 
			;THROW 60000, N'You cannot revise an accepted quote', 1;
		END

		EXEC SCore.UpsertDataObject
			@Guid					= @TargetGuid,
			@SchemeName				= N'SSop',
			@ObjectName				= N'Quotes',
			@IncludeDefaultSecurity = 1,
			@IsInsert				= @IsInsert

		INSERT SSop.Quotes
				(
					RowStatus,
					Guid,
					OrganisationalUnitID,
					QuotingUserId,
					Number,
					UprnId,
					ClientAccountId,
					ClientAddressId,
					ClientContactId,
					ContractID,
					Date,
					Overview,
					ExpiryDate,
					QuoteSourceId,
					IsSubjectToNDA,
					AgentAccountId,
					AgentAddressId,
					AgentContactId,
					ExternalReference,
					FeeCap,
					RevisionNumber,
					OriginalQuoteId
				)
			SELECT
					0,
					@TargetGuid,
					q.OrganisationalUnitID,
					q.QuotingUserId,
					q.Number,
					q.UprnId,
					q.ClientAccountId,
					q.ClientAddressId,
					q.ClientContactId,
					q.ContractID,
					GETDATE(),
					q.Overview,
					DATEADD(MONTH,
					6,
					GETDATE()
					),
					q.QuoteSourceId,
					q.IsSubjectToNDA,
					q.AgentAccountId,
					q.AgentAddressId,
					q.AgentContactId,
					q.ExternalReference,
					q.FeeCap,
					ISNULL(latest_revision.rev, 0) + 1,
					CASE
							WHEN q.OriginalQuoteId = (-1) THEN
								q.ID
							ELSE
							q.OriginalQuoteId
					END
			FROM
					SSop.Quotes AS q
			OUTER APPLY
					(
						SELECT
								MAX(q1.RevisionNumber) rev
						FROM
								SSop.Quotes q1
						WHERE
								(q1.OriginalQuoteId = CASE
										WHEN q.OriginalQuoteId = (-1) THEN
											q.ID
										ELSE
										q.OriginalQuoteId
								END)
					) latest_revision
			WHERE
					(q.ID = @SourceID);

		SELECT
				@ID = SCOPE_IDENTITY();

		-- Build the collection of sections to duplicate. 
		DECLARE @QuoteSections SCore.TwoGuidUniqueList

		INSERT @QuoteSections
				(
					GuidValue,
					GuidValueTwo
				)
			SELECT
					qs.Guid,
					NEWID()
			FROM
					SSop.QuoteSections qs
			WHERE
					(qs.QuoteId = @SourceID)
					AND (qs.RowStatus NOT IN (0, 254))

		-- Build the collection of items to duplicate. 
		DECLARE @QuoteItems SCore.TwoGuidUniqueList

		INSERT @QuoteItems
				(
					GuidValue,
					GuidValueTwo
				)
			SELECT
					qi.Guid,
					NEWID()
			FROM
					SSop.QuoteItems qi
			JOIN
					SSop.QuoteSections qs ON (qs.ID = qi.QuoteSectionId)
			WHERE
					(qs.QuoteId = @SourceID)
					AND (qi.RowStatus NOT IN (0, 254))
					AND (qs.RowStatus NOT IN (0, 254))

		-- Build the collection of payment stages to duplicate
		DECLARE @QuotePaymentStages SCore.TwoGuidUniqueList

		INSERT @QuotePaymentStages
				(
					GuidValue,
					GuidValueTwo
				)
			SELECT
					qps.Guid,
					NEWID()
			FROM
					SSop.QuotePaymentStages qps
			WHERE
					(qps.QuoteId = @SourceID)
					AND (qps.RowStatus NOT IN (0, 254))

		-- Create the data objects. 
		DECLARE @NewGuidList SCore.GuidUniqueList

		INSERT @NewGuidList
				(
					GuidValue
				)
			SELECT
					GuidValueTwo
			FROM
					@QuoteSections

		EXEC SCore.DataObjectBulkUpsert
			@GuidList   = @NewGuidList,				-- GuidUniqueList
			@SchemeName = N'SSop',				-- nvarchar(255)
			@ObjectName = N'QuoteSections',				-- nvarchar(255)
			@IsInsert   = @IsInsert OUTPUT	-- bit

		DELETE FROM
		@NewGuidList

		INSERT @NewGuidList
				(
					GuidValue
				)
			SELECT
					GuidValueTwo
			FROM
					@QuoteItems

		EXEC SCore.DataObjectBulkUpsert
			@GuidList   = @NewGuidList,				-- GuidUniqueList
			@SchemeName = N'SSop',				-- nvarchar(255)
			@ObjectName = N'QuoteItems',				-- nvarchar(255)
			@IsInsert   = @IsInsert OUTPUT	-- bit	

		DELETE FROM
		@NewGuidList		
		INSERT @NewGuidList
				(
					GuidValue
				)
			SELECT
					GuidValueTwo
			FROM
					@QuotePaymentStages

		EXEC SCore.DataObjectBulkUpsert
			@GuidList   = @NewGuidList,				-- GuidUniqueList
			@SchemeName = N'SSop',				-- nvarchar(255)
			@ObjectName = N'QuotePaymentStages',				-- nvarchar(255)
			@IsInsert   = @IsInsert OUTPUT	-- bit	

		-- Duplicate the Quote Sections. 
		INSERT SSop.QuoteSections
				(
					RowStatus,
					Guid,
					QuoteId,
					Name,
					Overview,
					ShowProducts,
					ConsolidateJobs,
					SortOrder,
					ValueOfWorkId,
					RibaStageId,
					CombineWithSectionId,
					NumberOfMeetings,
					NumberOfSiteVisits,
					InvoiceScheduleId
				)
			SELECT
					1,
					qsl.GuidValueTwo,
					@ID,
					qs.Name,
					qs.Overview,
					qs.ShowProducts,
					qs.ConsolidateJobs,
					qs.SortOrder,
					qs.ValueOfWorkId,
					qs.RibaStageId,
					qs.CombineWithSectionId,
					qs.NumberOfMeetings,
					qs.NumberOfSiteVisits,
					qs.InvoiceScheduleId
			FROM
					SSop.QuoteSections qs
			JOIN
					@QuoteSections qsl ON (qs.Guid = qsl.GuidValue)

		-- Duplicate the Quote Items. 
		INSERT SSop.QuoteItems
				(
					RowStatus,
					Guid,
					QuoteSectionId,
					ProductId,
					Details,
					Net,
					VatRate,
					DoNotConsolidateJob,
					SortOrder,
					Quantity
				)
			SELECT
					1,
					qil.GuidValueTwo,
					nqs.ID,
					qi.ProductId,
					qi.Details,
					qi.Net,
					qi.VatRate,
					qi.DoNotConsolidateJob,
					qi.SortOrder,
					qi.Quantity
			FROM
					SSop.QuoteItems qi
			JOIN
					@QuoteItems qil ON (qil.GuidValue = qi.Guid)
			JOIN
					SSop.QuoteSections oqs ON (oqs.ID = qi.QuoteSectionId)
			JOIN
					@QuoteSections qsl ON (qsl.GuidValue = oqs.Guid)
			JOIN
					SSop.QuoteSections nqs ON (nqs.Guid = qsl.GuidValueTwo)

		-- Duplicate the Quote Payment Stages 
		INSERT INTO SSop.QuotePaymentStages
					(
						RowStatus,
						Guid,
						QuoteId,
						PaymentFrequencyTypeId,
						PaymentFrequency,
						Value,
						PercentageOfTotal,
						PayAfterStageId
					)
			SELECT
					1,
					qpsl.GuidValueTwo,
					@Id,
					qps.PaymentFrequencyTypeId,
					qps.PaymentFrequency,
					qps.Value,
					qps.PercentageOfTotal,
					qps.PayAfterStageId
			FROM
					SSop.QuotePaymentStages qps
			JOIN
					@QuotePaymentStages qpsl ON (qps.Guid = qpsl.GuidValue)

		UPDATE  SSop.Quotes
		SET		RowStatus = 1
		WHERE
			(ID = @ID);
	END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

