--
-- Create or alter function [SSop].[tvf_QuotesValidate]
--
GO


CREATE OR ALTER FUNCTION [SSop].[tvf_QuotesValidate]
	(
		@Guid UNIQUEIDENTIFIER,
		@DateSent DATE,
		@DeadDate DATE,
		@DateRejected DATE,
		@IsFinal BIT,
		@RevisionNumber INT,
		@OrganisationalUnitGuid UNIQUEIDENTIFIER
	)
RETURNS @ValidationResult TABLE
	(
		ID INT IDENTITY(1, 1) NOT NULL,
		TargetGuid UNIQUEIDENTIFIER NOT NULL DEFAULT ('00000000-0000-0000-0000-000000000000'),
		TargetType CHAR(1) NOT NULL DEFAULT (''),
		IsReadOnly BIT NOT NULL DEFAULT ((0)),
		IsHidden BIT NOT NULL DEFAULT ((0)),
		IsInvalid BIT NOT NULL DEFAULT ((0)),
		IsInformationOnly BIT NOT NULL DEFAULT ((0)),
		Message NVARCHAR(2000) NOT NULL DEFAULT ('')
	)
AS
BEGIN
	DECLARE @EntityTypeGuid UNIQUEIDENTIFIER = '1c4794c1-f956-4c32-b886-5500ac778a56';

	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.QuoteItems AS qi
		 JOIN	SSop.Quotes		AS q ON (q.ID = qi.QuoteId)
		 WHERE	(q.Guid			 = @Guid)
			AND (qi.RowStatus NOT IN (0, 254))
			AND (qi.CreatedJobId > 0)
	 )
	   )
	OR	(@DeadDate IS NOT NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		VALUES
			 (
				 @EntityTypeGuid,
				 N'E',
				 1,
				 0,
				 0,
				 N''
			 );
	END;

	-- Hide fields from CDM based quotes 
	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SCore.OrganisationalUnits AS ou
		 WHERE	(ou.Guid = @OrganisationalUnitGuid)
			AND (ou.Name LIKE N'CDM%')
	 )
	   )
	BEGIN

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'FeeCap');
	END;

	/*IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.QuoteSections AS qs
		 JOIN	SSop.Quotes		   AS q ON (q.ID = qs.QuoteId)
		 WHERE	(q.Guid			= @Guid)
			AND (qs.RibaStageId < 0)
			AND (qs.RowStatus NOT IN (0, 254))
	 )
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				0,
				1,
				N'All sections must have a Stage set.'
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'Number');
	END;*/

	IF (@RevisionNumber < 1)
	BEGIN

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= (N'RevisionNumber'));


	END;

	/* Don't allow the user to progress the status further than Send until the quote has been marked as Sent. */
	IF (@DateSent IS NULL)
	BEGIN

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name IN (N'DateAccepted', N'DateRejected', N'RejectionReason', N'ChaseDate1', N'ChaseDate2'));


	END;

	/* Once the quote has been sent you can't unset it as "Is Final" */
	IF (@DateSent IS NOT NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'IsFinal');
	END;

	/* Don't allow the quote to be sent until it has been set as "Is Final" */
	IF (@IsFinal = 0)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'DateSent');
	END;

	/* Hide Rejection Reason if the Quote hasn't been rejected. */
	IF (@DateRejected IS NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'RejectionReason');
	END;

	IF (@IsFinal = 1)
   AND	(NOT EXISTS
	 (
		 SELECT 1
		 FROM	SSop.Quotes AS q
		 WHERE	(q.Guid						= @Guid)
			AND (q.LegacyId IS NOT NULL)
			AND
				(
					(q.OrganisationalUnitID < 0)
				 OR (q.QuotingUserId		< 0)
				 OR (q.QuotingConsultantId	< 0)
				)
	 )
		)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name NOT IN (N'ChaseDate2', N'ChaseDate1', N'RejectionReason', N'DateRejected', N'DateAccepted',
									N'IsFinal', N'DateSent'
								   )
				);


		IF (ISNULL (
				 (
					 SELECT SUM (qit.LineNet)
					 FROM	SSop.QuoteItemTotals AS qit
					 JOIN	SSop.QuoteItems		 AS qi ON (qi.ID = qit.ID)
					 JOIN	SSop.Quotes			 AS q ON (q.ID	 = qi.QuoteId)
					 WHERE	(q.Guid = @Guid)
						AND (qi.RowStatus NOT IN (0, 254))
				 ),
				 0
				   ) <= 0
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					0,
					1,
					N'A final quote must have a net value greater than 0.'
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	(epfvv.[Schema] = N'SSop')
				AND (epfvv.Hobt		= N'Quotes')
				AND (epfvv.Name		= N'IsFinal');
		END;

	END;

	RETURN;
END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SSop].[EnquiryServicesExtUpsert]
--
GO








CREATE OR ALTER PROCEDURE [SSop].[EnquiryServicesExtUpsert]
	(	@DateSent DATE,
		@DateAccepted DATE,
		@DateRejected DATE,
		@QuoteGuid UNIQUEIDENTIFIER,
		@Guid UNIQUEIDENTIFIER
	)
AS
BEGIN

	IF (@QuoteGuid = '00000000-0000-0000-0000-000000000000')
	BEGIN
		RETURN;
	END;

	IF (
		   @DateSent IS NOT NULL
		OR	@DateAccepted IS NOT NULL
		OR	@DateRejected IS NOT NULL
	   )
	BEGIN
		DECLARE @DeadDate DATE, 
				@IsFinal BIT, 
				@RevisionNumber INT, 
				@OrganisationalUnitGuid UNIQUEIDENTIFIER

		SELECT	@DeadDate = q.DeadDate, 
				@IsFinal = q.IsFinal,
				@RevisionNumber = q.RevisionNumber,
				@OrganisationalUnitGuid = ou.Guid
		FROM	SSop.Quotes AS q
		JOIN	SCore.OrganisationalUnits AS ou ON (ou.ID = q.OrganisationalUnitID)
		WHERE	(q.Guid = @QuoteGuid)

		DECLARE	@ValidationResults SCore.ValidationResult

		INSERT @ValidationResults
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, IsInformationOnly, Message)
		SELECT	qv.TargetGuid, qv.TargetType, qv.IsReadOnly, qv.IsHidden, qv.IsInvalid, qv.IsInformationOnly, qv.Message
		FROM	SSop.tvf_QuotesValidate(@QuoteGuid, @DateSent, @DeadDate, @DateRejected, @IsFinal, @RevisionNumber, @OrganisationalUnitGuid	) AS qv
		
		DECLARE	@ValidationMessage NVARCHAR(MAX) = SCore.GetValidationString(@ValidationResults)

		IF (@ValidationMessage <> N'')
		BEGIN			
			;THROW 60000, @ValidationMessage, 1
		END

		IF (EXISTS
				(
					SELECT	 1
					FROM	 @ValidationResults AS vr
					JOIN	SCore.EntityProperties AS ep ON (ep.Guid = vr.TargetGuid)
					WHERE	((vr.IsReadOnly = 1) OR (vr.IsHidden = 1))
						AND	(
								(ep.Name = N'DateSent' AND @DateSent IS NOT NULL)
							OR	(ep.Name = N'DateRejected' AND @DateRejected IS NOT NULL)
							OR	(ep.Name = N'DateAccepted' AND @DateAccepted IS NOT NULL)
							)
				)
			)
		BEGIN 
			;THROW 60000, N'You cannot change the Sent, Rejected or Accepted Date at the time, please check the state current of the quote.', 1
		END

		UPDATE	SSop.Quotes
		SET		DateSent = @DateSent,
				DateRejected = @DateRejected,
				DateAccepted = @DateAccepted
		WHERE	(Guid = @QuoteGuid);

	END;
END;



GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_QuoteItems]
--
GO




CREATE OR ALTER FUNCTION [SSop].[tvf_QuoteItems]
(
	@UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
    --WITH SCHEMABINDING
AS RETURN	
SELECT  qi.ID,
        qi.RowStatus,
        qi.Guid,
		qi.SortOrder,
		qi.Details,
		p.Code,
		qi.Quantity,
		qi.Net,
		qit.Vat,
		qit.Gross,
		qit.LineNet,
		qit.LineVat,
		qit.LineGross
FROM    SSop.QuoteItems qi
JOIN	SSop.Quotes q ON (q.ID = qi.QuoteId)
JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
JOIN	SProd.Products p ON (p.ID = qi.ProductId)	
WHERE   (qi.RowStatus NOT IN (0, 254))
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(qi.Guid, @UserId) oscr
			)
		)
	AND	(q.Guid = @ParentGuid)
UNION ALL 
SELECT	-2,
		1,
		'00000000-0000-0000-0000-000000000000',
		999,
		N'Total',
		N'',
		SUM(qi.Quantity),
		SUM(qi.Net),
		SUM(qit.Vat),
		SUM(qit.Gross),
		SUM(qit.LineNet),
		SUM(qit.LineVat),
		SUM(qit.LineGross)
FROM    SSop.QuoteItems qi
JOIN	SSop.Quotes q ON (q.ID = qi.QuoteId)
JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
WHERE   (qi.RowStatus NOT IN (0, 254))
	AND	(q.Guid = @ParentGuid)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_QuoteFeeDrawdown]
--
GO

CREATE OR ALTER FUNCTION [SSop].[tvf_QuoteFeeDrawdown] 
(
    @UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
       --WITH SCHEMABINDING
AS
RETURN 
SELECT		q.ID,
			q.RowStatus,
			q.Guid,
			CASE
				WHEN rs.Number = 0 THEN N'Fee Cap'
				WHEN rs.Number = 99 THEN N'Pre-Construction'
				WHEN rs.Number = 999 THEN N'Construction'
				ELSE CONVERT (	 NVARCHAR(10),
								 rs.Number
							 )
			END AS Stage,
			ISNULL(CASE rs.Number
				WHEN 0 THEN q.FeeCap
				ELSE stages.Net
			END, 0) AS Quoted
FROM		SSop.Quotes		AS q
CROSS JOIN	SJob.RibaStages AS rs
OUTER APPLY
			(
				SELECT		CASE WHEN qi.ProvideAtStageID = -1 THEN 2 ELSE qi.ProvideAtStageID END  AS RibaStage,
							SUM(qit.LineNet) AS Net
				FROM		SSop.QuoteItems		AS qi
				JOIN		SSop.QuoteItemTotals AS qit ON (qi.ID = qit.ID)
				WHERE		(qi.QuoteId = q.ID)
						AND (qi.RowStatus NOT IN (0, 254))
						AND	(CASE WHEN qi.ProvideAtStageID = -1 THEN 2 ELSE qi.ProvideAtStageID END = rs.ID)
				GROUP BY	CASE WHEN qi.ProvideAtStageID = -1 THEN 2 ELSE qi.ProvideAtStageID END
			)				AS stages
WHERE		(rs.ID	> 0)
		AND (q.Guid = @ParentGuid)
		AND	(
				(
						(rs.IsRealStage = 1)
						AND	(NOT EXISTS
								(
									SELECT	1
									FROM	SSop.QuoteSections eqs
									JOIN	SJob.RibaStages ers ON (ers.ID = eqs.RibaStageId)
									WHERE	(eqs.QuoteId = q.ID)
										AND	(eqs.RowStatus NOT IN (0, 254))
										AND	(ers.Number IN (99, 999))
								)
							)
					)
				OR	(
						(rs.IsRealStage = 0)
						AND	(EXISTS
								(
									SELECT	1
									FROM	SSop.QuoteSections eqs
									JOIN	SJob.RibaStages ers ON (ers.ID = eqs.RibaStageId)
									WHERE	(eqs.QuoteId = q.ID)
										AND	(eqs.RowStatus NOT IN (0, 254))
										AND	(ers.Number IN (99, 999))
								)
							)
					)
			)
UNION ALL
SELECT	q.Id,
		q.RowStatus,
		q.Guid,
		N'Total (ex. Fee Cap.)',
		sections.Total AS Quoted
FROM	SSop.Quotes q
OUTER APPLY (
	SELECT SUM(qit.LineNet) AS Total
	FROM	SSop.QuoteItems  qi
	JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
	WHERE	(qi.QuoteId = q.ID)
) AS sections
WHERE	(q.Guid = @ParentGuid)
UNION ALL
SELECT	q.Id,
		q.RowStatus,
		q.Guid,
		N'Total (inc. Fee Cap.)',
		sections.Total + q.FeeCap AS Quoted
FROM	SSop.Quotes q
OUTER APPLY (
	SELECT SUM(qit.LineNet) AS Total
	FROM	SSop.QuoteItems  qi
	JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
	WHERE	(qi.QuoteId = q.ID)
) AS sections
WHERE	(q.Guid = @ParentGuid)

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[Quote_MergeInfo]
--
GO


CREATE OR ALTER VIEW [SSop].[Quote_MergeInfo]
AS
SELECT		q.ID,
			q.RowStatus,
			q.RowVersion,
			q.Guid,
			q.Number																					 AS QuoteNumber,
			e.DescriptionOfWorks																		 AS QuoteOverview,
			q.Date																						 AS QuoteDate,
			q.FeeCap,
																																	/* UPRN */
			uprn.Number																					 AS UPRN,
			uprn.AddressLine1																			 AS PropertyAddressLine1,	-- was PropertyAddress1
			uprn.AddressLine2																			 AS PropertyAddressLine2,	-- was PropertyAddress2
			uprn.AddressLine3																			 AS PropertyAddressLine3,	-- was PropertyAddress3
			uprn.Town																					 AS PropertyTown,
			uprnc.Name																					 AS PropertyCounty,
			uprn.Postcode																				 AS PropertyPostcode,
			uprn.FormattedAddressComma																	 AS PropertyAddress,
			uprn.FormattedAddressCR																		 AS PropertyAddressBlock,
			COALESCE (	 uprn.Name + ' ',
						 ''
					 ) + COALESCE (	  uprn.Number + ' ',
									  ''
								  ) + uprn.AddressLine1													 AS PropertyShortAddress,
																																	/* Client */
			cacc.Name																					 AS ClientName,				-- was [Label] or [Title]
			cacc.CompanyRegistrationNumber																 AS ClientCompanyRegNo,
			cadd.AddressLine1																			 AS ClientAddressLine1,		-- was ClientAddress1
			cadd.AddressLine2																			 AS ClientAddressLine2,		-- was ClientAddress2
			cadd.AddressLine3																			 AS ClientAddressLine3,		-- was ClientAddress3
			cadd.Town																					 AS ClientTown,
			caddc.Name																					 AS ClientCounty,
			cadd.Postcode																				 AS ClientPostcode,
			cadd.FormattedAddressComma																	 AS ClientAddress,			-- was AddressClient
			cadd.FormattedAddressCR																		 AS ClientAddressBlock,
			ccon.DisplayName																			 AS ClientContactName,
			ccon.FirstName																				 AS ClientFirstName,
			ccon.Surname																				 AS ClientSurname,
			ccon.Email																					 AS ClientEmail,
			ccon.Phone																					 AS ClientPhone,
			ccon.Mobile																					 AS ClientMobile,
			CASE
				WHEN q.SendInfoToClient = 1 THEN cacc.Name
				ELSE aacc.Name
			END																							 AS RecipientName,			-- was [Label] or [Title]
			CASE
				WHEN q.SendInfoToClient = 1 THEN cacc.CompanyRegistrationNumber
				ELSE aacc.CompanyRegistrationNumber
			END																							 AS RecipientCompanyRegNo,
			CASE
				WHEN q.SendInfoToClient = 1 THEN cadd.AddressLine1
				ELSE aadd.AddressLine1
			END																							 AS RecipientAddressLine1,	-- was ClientAddress1
			CASE
				WHEN q.SendInfoToClient = 1 THEN cadd.AddressLine2
				ELSE aadd.AddressLine2
			END																							 AS RecipientAddressLine2,	-- was ClientAddress2
			CASE
				WHEN q.SendInfoToClient = 1 THEN cadd.AddressLine3
				ELSE aadd.AddressLine3
			END																							 AS RecipientAddressLine3,	-- was ClientAddress3
			CASE
				WHEN q.SendInfoToClient = 1 THEN cadd.Town
				ELSE aadd.Town
			END																							 AS RecipientTown,
			CASE
				WHEN q.SendInfoToClient = 1 THEN caddc.Name
				ELSE aaddc.Name
			END																							 AS RecipientCounty,
			CASE
				WHEN q.SendInfoToClient = 1 THEN cadd.Postcode
				ELSE aadd.Postcode
			END																							 AS RecipientPostcode,
			CASE
				WHEN q.SendInfoToClient = 1 THEN cadd.FormattedAddressComma
				ELSE aadd.FormattedAddressComma
			END																							 AS RecipientAddress,		-- was AddressClient
			CASE
				WHEN q.SendInfoToClient = 1 THEN cadd.FormattedAddressCR
				ELSE aadd.FormattedAddressCR
			END																							 AS RecipientAddressBlock,
			CASE
				WHEN q.SendInfoToClient = 1 THEN ccon.DisplayName
				ELSE acon.DisplayName
			END																							 AS RecipientContactName,
			CASE
				WHEN q.SendInfoToClient = 1 THEN ccon.FirstName
				ELSE acon.FirstName
			END																							 AS RecipientFirstName,
			CASE
				WHEN q.SendInfoToClient = 1 THEN ccon.Surname
				ELSE ccon.Surname
			END																							 AS RecipientSurname,
			CASE
				WHEN q.SendInfoToClient = 1 THEN ccon.Email
				ELSE ccon.Email
			END																							 AS RecipientEmail,
			CASE
				WHEN q.SendInfoToClient = 1 THEN ccon.Phone
				ELSE ccon.Phone
			END																							 AS RecipientPhone,
			CASE
				WHEN q.SendInfoToClient = 1 THEN ccon.Mobile
				ELSE ccon.Mobile
			END																							 AS RecipientMobile,

																																	/* Company */
			offa.Name																					 AS OfficialName,
			offa.AddressLine1																			 AS OfficialAddressLine1,
			offa.AddressLine2																			 AS OfficialAddressLine2,
			offa.AddressLine3																			 AS OfficialAddressLine3,
			offa.Town																					 AS OfficialTown,
			offac.Name																					 AS OfficialCounty,
			offa.Postcode																				 AS OfficialPostcode,
			offcon.Email																				 AS OfficialEmail,
			offcon.Phone																				 AS OfficialPhone,
			offcon.Mobile																				 AS OfficialMobile,
																																	/* Fee Drawdown*/
			DrawDown.Stage1Net,
			DrawDown.Stage2Net,
			DrawDown.Stage3Net,
			DrawDown.Stage4Net,
			DrawDown.Stage5Net,
			DrawDown.Stage6Net,
			DrawDown.Stage7Net,
			DrawDown.PreConstruction,
			DrawDown.Construction,
			DrawDown.Stage1Net + DrawDown.Stage2Net + DrawDown.Stage3Net + DrawDown.Stage4Net + DrawDown.Stage5Net
			+ DrawDown.Stage6Net + DrawDown.Stage7Net + DrawDown.PreConstruction + DrawDown.Construction AS TotalNetFees,

																																	/* Quoting User */
			quconm.Email																				 AS QuotingUserEmail,
			qu.FullName																					 AS QuotingUserName,
			qu.FullName + N' ' + COALESCE (	  qucon.PostNominals,
											  ''
										  )																 AS QuotingUserPostNominals,
			qucon.Initials																				 AS QuotingUserInitials,
			qu.JobTitle																					 AS QuotingUserJobTitle,
			qcconm.Email																				 AS QuotingConsultantEmail,
			qc.FullName																					 AS QuotingConsultantName,
			qc.FullName + N' ' + COALESCE (	  qccon.PostNominals,
											  ''
										  )																 AS QuotingConsultantPostNominals,
			qccon.Initials																				 AS QuotingConsultantInitials,
			qc.JobTitle																					 AS QuotingConsultantJobTitle
FROM		SSop.Quotes				  AS q
JOIN		SSop.EnquiryServices	  AS es ON (es.ID = q.EnquiryServiceID)
JOIN		SSop.Enquiries			  AS e ON (e.ID = es.EnquiryId)
JOIN		SCore.OrganisationalUnits AS ou ON (ou.ID = q.OrganisationalUnitID)
JOIN		SCrm.Contact_MergeInfo	  AS offcon ON (offcon.ID = ou.OfficialContactId)
JOIN		SCrm.Addresses			  AS offa ON (offa.ID = ou.OfficialAddressId)
JOIN		SCrm.Counties			  AS offac ON (offac.ID = offa.CountyID)
JOIN		SJob.Properties			  AS uprn ON (uprn.ID = e.PropertyId)
JOIN		SCrm.Counties			  AS uprnc ON (uprnc.ID = uprn.CountyId)
JOIN		SCrm.Accounts			  AS cacc ON (cacc.ID = e.ClientAccountId)
JOIN		SCrm.AccountAddresses	  AS caad ON (caad.ID = e.ClientAddressId)
JOIN		SCrm.Addresses			  AS cadd ON (cadd.ID = caad.AddressID)
JOIN		SCrm.AccountContacts	  AS cac ON (cac.ID = e.ClientAccountContactId)
JOIN		SCrm.Contact_MergeInfo	  AS ccon ON (ccon.ID = cac.ContactID)
JOIN		SCrm.Counties			  AS caddc ON (caddc.ID = cadd.CountyID)
JOIN		SCore.Identities		  AS qu ON (qu.ID = q.QuotingUserId)
JOIN		SCrm.Accounts			  AS aacc ON (aacc.ID = e.AgentAccountId)
JOIN		SCrm.AccountAddresses	  AS aaad ON (aaad.ID = e.AgentAddressId)
JOIN		SCrm.Addresses			  AS aadd ON (aadd.ID = aaad.AddressID)
JOIN		SCrm.AccountContacts	  AS aac ON (aac.ID = e.AgentAccountContactId)
JOIN		SCrm.Contact_MergeInfo	  AS acon ON (acon.ID = aac.ContactID)
JOIN		SCrm.Counties			  AS aaddc ON (aaddc.ID = aadd.CountyID)
LEFT JOIN	SCrm.Contacts			  AS qucon ON (qucon.ID = qu.ContactId)
LEFT JOIN	SCrm.Contact_MergeInfo	  AS quconm ON (quconm.ID = qucon.ID)
JOIN		SCore.Identities		  AS qc ON (qc.ID = q.QuotingConsultantId)
LEFT JOIN	SCrm.Contacts			  AS qccon ON (qccon.ID = qc.ContactId)
LEFT JOIN	SCrm.Contact_MergeInfo	  AS qcconm ON (qcconm.ID = qccon.ID)
OUTER APPLY
			(
				SELECT	ID,
						ISNULL (   [1],
								   0
							   ) AS Stage1Net,
						ISNULL (   [2],
								   0
							   ) AS Stage2Net,
						ISNULL (   [3],
								   0
							   ) AS Stage3Net,
						ISNULL (   [4],
								   0
							   ) AS Stage4Net,
						ISNULL (   [5],
								   0
							   ) AS Stage5Net,
						ISNULL (   [6],
								   0
							   ) AS Stage6Net,
						ISNULL (   [7],
								   0
							   ) AS Stage7Net,
						ISNULL (   [99],
								   0
							   ) AS PreConstruction,
						ISNULL (   [999],
								   0
							   ) AS Construction
				FROM
						(
							SELECT	ID,
									Stage,
									Quoted
							FROM	SSop.tvf_QuoteFeeDrawdown (	  q.QuotingUserId,
																  q.Guid
															  )
						) AS d
				PIVOT
					(
						MIN(Quoted)
						FOR Stage IN ([1], [2], [3], [4], [5], [6], [7], [99], [999])
					) AS qfd
			)						  AS DrawDown;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

