--
-- Create or alter view [SSop].[EnquiryService_ExtendedInfo]
--
GO





CREATE OR ALTER VIEW	[SSop].[EnquiryService_ExtendedInfo]
    --WITH SCHEMABINDING
AS
SELECT	es.Id,
		es.RowStatus,
		es.RowVersion,
		es.Guid,
		ISNULL(quote.QuoteID, -1) AS QuoteID,
		quote.DateAccepted,
		quote.DateSent,
		quote.DateRejected,
		quote.QuoteNet,
		ISNULL(quote.Number, 0) AS Number,
		ISNULL(Quote.RevisionNumber, 0) AS RevisionNumber
FROM	SSop.EnquiryServices es
OUTER APPLY 
	(
		SELECT	q.ID AS QuoteID,
				q.DateAccepted,
				q.DateSent, 
				q.DateRejected,
				q.Number,
				q.RevisionNumber,
				QuoteLines.Net QuoteNet
		FROM	SSop.Quotes AS q
		OUTER APPLY (
			SELECT	SUM(qit.LineNet) AS Net
			FROM	SSop.QuoteItems AS qi 
			JOIN	SSop.QuoteItemTotals AS qit ON (qit.ID = qi.ID)
			WHERE	(qi.QuoteId = q.ID)
				AND	(qi.RowStatus NOT IN (0, 254))
		) QuoteLines
		WHERE	(q.EnquiryServiceID = es.ID)
			AND	(q.EnquiryServiceID > -1)
			AND	(NOT EXISTS
					(
						SELECT	1
						FROM	SSop.Quotes AS q2
						WHERE	(q2.EnquiryServiceID = q.EnquiryServiceID)
							AND	(q2.RevisionNumber > q.RevisionNumber)
					)
				)
	) AS Quote

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SSop].[EnquiriesRevise]
--
GO




CREATE OR ALTER PROCEDURE [SSop].[EnquiriesRevise] @SourceGuid UNIQUEIDENTIFIER,
									 @TargetGuid UNIQUEIDENTIFIER
AS
BEGIN

	DECLARE @SourceID INT,
			@ID		  INT,
			@IsInsert BIT;

	SELECT	@SourceID = ID
	FROM	SSop.Enquiries
	WHERE	(Guid = @SourceGuid);

	IF (@@ROWCOUNT > 1)
	BEGIN
		;
		THROW 60000, N'Invalid source Enquiry', 1;
	END;

	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.Enquiries AS e
		 WHERE	(e.Guid = @SourceGuid)
			AND (EXISTS
					(
						SELECT	1
						FROM	SSop.EnquiryServices AS es
						JOIN	SSop.EnquiryService_ExtendedInfo esei ON (esei.Id = es.ID)
						WHERE	(es.EnquiryId = e.ID)
							AND	(esei.DateAccepted IS NOT NULL)
					)
				)
	 )
	   )
	BEGIN
		; THROW 60000, N'You cannot revise an accepted Enquiry', 1;
	END;

	EXEC SCore.UpsertDataObject @Guid = @TargetGuid,
								@SchemeName = N'SSop',
								@ObjectName = N'Enquiries',
								@IncludeDefaultSecurity = 1,
								@IsInsert = @IsInsert;

	INSERT	SSop.Enquiries
		 (RowStatus,
		  Guid,
		  OrganisationalUnitID,
		  Date,
		  CreatedByUserId,
		  Number,
		  PropertyId,
		  PropertyNameNumber,
		  PropertyAddressLine1,
		  PropertyAddressLine2,
		  PropertyAddressLine3,
		  PropertyTown,
		  PropertyCountyId,
		  PropertyPostCode,
		  PropertyCountryId,
		  ClientAccountId,
		  ClientAddressId,
		  ClientAccountContactId,
		  ClientName,
		  ClientAddressNameNumber,
		  ClientAddressLine1,
		  ClientAddressLine2,
		  ClientAddressLine3,
		  ClientAddressTown,
		  ClientAddressCountyId,
		  ClientAddressPostCode,
		  ClientAddressCountryId,
		  AgentAccountId,
		  AgentAddressId,
		  AgentAccountContactId,
		  AgentName,
		  AgentAddressNameNumber,
		  AgentAddressLine1,
		  AgentAddressLine2,
		  AgentAddressLine3,
		  AgentTown,
		  AgentCountyId,
		  AgentAddressPostCode,
		  AgentCountryId,
		  DescriptionOfWorks,
		  ValueOfWork,
		  CurrentProjectRibaStageID,
		  RibaStage0Months,
		  RibaStage1Months,
		  RibaStage2Months,
		  RibaStage3Months,
		  RibaStage4Months,
		  RibaStage5Months,
		  RibaStage6Months,
		  RibaStage7Months,
		  PreConstructionStageMonths,
		  ConstructionStageMonths,
		  SendInfoToClient,
		  SendInfoToAgent,
		  KeyDates,
		  ExpectedProcurementRoute,
		  Notes,
		  EnquirySourceId,
		  IsReadyForQuoteReview,
		  QuotingDeadlineDate,
		  DeclinedToQuoteDate,
		  DeclinedToQuoteReason,
		  ExternalReference,
		  ProjectId,
		  IsSubjectToNDA,
		  DeadDate,
		  ChaseDate1,
		  ChaseDate2,
		  IsClientFinanceAccount,
		  FinanceAccountId,
		  FinanceAddressId,
		  FinanceContactId,
		  FinanceAccountName,
		  FinanceAddressNameNumber,
		  FinanceAddressLine1,
		  FinanceAddressLine2,
		  FinanceAddressLine3,
		  FinanceTown,
		  FinanceCountyId,
		  FinancePostCode,
		  EnterNewClientDetails,
		  EnterNewAgentDetails,
		  EnterNewFinanceDetails,
		  EnterNewStructureDetails,
		  SignatoryIdentityId,
		  ProposalLetter,
		  Revision,
		  OriginalEnquiryId)
	SELECT	0,								-- RowStatus - tinyint
			@TargetGuid,					-- Guid - uniqueidentifier
			e.OrganisationalUnitID,			-- OrganisationalUnitID - int
			e.Date,							-- Date - datetime2(7)
			e.CreatedByUserId,				-- CreatedByUserId - int
			e.Number,							-- Number - nvarchar(50)
			e.PropertyId,					-- PropertyId - int
			e.PropertyNameNumber,			-- PropertyNameNumber - nvarchar(100)
			e.PropertyAddressLine1,			-- PropertyAddressLine1 - nvarchar(255)
			e.PropertyAddressLine2,			-- PropertyAddressLine2 - nvarchar(255)
			e.PropertyAddressLine3,			-- PropertyAddressLine3 - nvarchar(255)
			e.PropertyTown,					-- PropertyTown - nvarchar(255)
			e.PropertyCountyId,				-- PropertyCountyId - int
			e.PropertyPostCode,				-- PropertyPostCode - nvarchar(30)
			e.PropertyCountryId,			-- PropertyCountryId - int
			e.ClientAccountId,				-- ClientAccountId - int
			e.ClientAddressId,				-- ClientAddressId - int
			e.ClientAccountContactId,		-- ClientAccountContactId - int
			e.ClientName,					-- ClientName - nvarchar(250)
			e.ClientAddressNameNumber,		-- ClientAddressNameNumber - nvarchar(100)
			e.ClientAddressLine1,			-- ClientAddressLine1 - nvarchar(255)
			e.ClientAddressLine2,			-- ClientAddressLine2 - nvarchar(255)
			e.ClientAddressLine3,			-- ClientAddressLine3 - nvarchar(255)
			e.ClientAddressTown,			-- ClientAddressTown - nvarchar(255)
			e.ClientAddressCountyId,		-- ClientAddressCountyId - int
			e.ClientAddressPostCode,		-- ClientAddressPostCode - nvarchar(30)
			e.ClientAddressCountryId,		-- ClientAddressCountryId - int
			e.AgentAccountId,				-- AgentAccountId - int
			e.AgentAddressId,				-- AgentAddressId - int
			e.AgentAccountContactId,		-- AgentAccountContactId - int
			e.AgentName,					-- AgentName - nvarchar(250)
			e.AgentAddressNameNumber,		-- AgentAddressNameNumber - nvarchar(100)
			e.AgentAddressLine1,			-- AgentAddressLine1 - nvarchar(255)
			e.AgentAddressLine2,			-- AgentAddressLine2 - nvarchar(255)
			e.AgentAddressLine3,			-- AgentAddressLine3 - nvarchar(255)
			e.AgentTown,					-- AgentTown - nvarchar(255)
			e.AgentCountyId,				-- AgentCountyId - int
			e.AgentAddressPostCode,			-- AgentAddressPostCode - nvarchar(30)
			e.AgentCountryId,				-- AgentCountryId - int
			e.DescriptionOfWorks,			-- DescriptionOfWorks - nvarchar(4000)
			e.ValueOfWork,					-- ValueOfWork - decimal(19, 2)
			e.CurrentProjectRibaStageID,	-- CurrentProjectRibaStageID - int
			e.RibaStage0Months,				-- RibaStage0Months - int
			e.RibaStage1Months,				-- RibaStage1Months - int
			e.RibaStage2Months,				-- RibaStage2Months - int
			e.RibaStage3Months,				-- RibaStage3Months - int
			e.RibaStage4Months,				-- RibaStage4Months - int
			e.RibaStage5Months,				-- RibaStage5Months - int
			e.RibaStage6Months,				-- RibaStage6Months - int
			e.RibaStage7Months,				-- RibaStage7Months - int
			e.PreConstructionStageMonths,	-- PreConstructionStageMonths - int
			e.ConstructionStageMonths,		-- ConstructionStageMonths - int
			e.SendInfoToClient,				-- SendInfoToClient - bit
			e.SendInfoToAgent,				-- SendInfoToAgent - bit
			e.KeyDates,						-- KeyDates - nvarchar(2000)
			e.ExpectedProcurementRoute,		-- ExpectedProcurementRoute - nvarchar(200)
			e.Notes,						-- Notes - nvarchar(max)
			e.EnquirySourceId,				-- EnquirySourceId - int
			(1),							-- IsReadyForQuoteReview - bit
			NULL,			-- QuotingDeadlineDate - date
			NULL,			-- DeclinedToQuoteDate - date
			N'',		-- DeclinedToQuoteReason - nvarchar(4000)
			e.ExternalReference,			-- ExternalReference - nvarchar(50)
			e.ProjectId,					-- ProjectId - int
			e.IsSubjectToNDA,				-- IsSubjectToNDA - bit
			NULL,							-- DeadDate - date
			NULL,							-- ChaseDate1 - date
			NULL,							-- ChaseDate2 - date
			e.IsClientFinanceAccount,		-- IsClientFinanceAccount - bit
			e.FinanceAccountId,				-- FinanceAccountId - int
			e.FinanceAddressId,				-- FinanceAddressId - int
			e.FinanceContactId,				-- FinanceContactId - int
			e.FinanceAccountName,			-- FinanceAccountName - nvarchar(250)
			e.FinanceAddressNameNumber,		-- FinanceAddressNameNumber - nvarchar(100)
			e.FinanceAddressLine1,			-- FinanceAddressLine1 - nvarchar(255)
			e.FinanceAddressLine2,			-- FinanceAddressLine2 - nvarchar(255)
			e.FinanceAddressLine3,			-- FinanceAddressLine3 - nvarchar(255)
			e.FinanceTown,					-- FinanceTown - nvarchar(255)
			e.FinanceContactId,				-- FinanceCountyId - int
			e.FinancePostCode,				-- FinancePostCode - nvarchar(30)
			e.EnterNewClientDetails,		-- EnterNewClientDetails - bit
			e.EnterNewAgentDetails,			-- EnterNewAgentDetails - bit
			e.EnterNewFinanceDetails,		-- EnterNewFinanceDetails - bit
			e.EnterNewStructureDetails,		-- EnterNewStructureDetails - bit
			e.SignatoryIdentityId,			-- SignatoryIdentityId - int
			e.ProposalLetter,				-- ProposalLetter - nvarchar(max)
			ISNULL (   latest_revision.rev,
					   0
				   ) + 1,
			CASE
				WHEN e.OriginalEnquiryId = (-1) THEN e.ID
				ELSE e.OriginalEnquiryId
			END
	FROM	SSop.Enquiries AS e
	OUTER APPLY
			(
				SELECT	MAX (q1.Revision) AS rev
				FROM	SSop.Enquiries AS q1
				WHERE	(q1.OriginalEnquiryId = CASE
												  WHEN e.OriginalEnquiryId = (-1) THEN e.ID
												  ELSE e.OriginalEnquiryId
											  END
						)
			)			AS latest_revision
	WHERE	(e.Guid = @SourceGuid);

	SELECT	@ID = SCOPE_IDENTITY ();

	-- Build the collection of Enquiry Services to duplicate. 
	DECLARE @EnquiryServices SCore.TwoGuidUniqueList;

	INSERT	@EnquiryServices
		 (GuidValue, GuidValueTwo)
	SELECT	es.Guid,
			NEWID ()
	FROM	SSop.EnquiryServices AS es
	JOIN	SSop.Enquiries		 AS e ON (e.ID = es.EnquiryId)
	WHERE	(e.Guid = @SourceGuid);

	-- Create the data objects. 
	DECLARE @NewGuidList SCore.GuidUniqueList;

	INSERT	@NewGuidList
		 (GuidValue)
	SELECT	GuidValueTwo
	FROM	@EnquiryServices;

	EXEC SCore.DataObjectBulkUpsert @GuidList = @NewGuidList,			-- GuidUniqueList
									@SchemeName = N'SSop',				-- nvarchar(255)
									@ObjectName = N'EnquiryServices',	-- nvarchar(255)
									@IsInsert = @IsInsert OUTPUT;		-- bit

	DELETE	FROM @NewGuidList;

	INSERT	SSop.EnquiryServices
		 (RowStatus, Guid, EnquiryId, JobTypeId, StartRibaStageId, EndRibaStageId, QuoteId)
	SELECT	1,
			es.GuidValueTwo,
			@ID,
			es2.JobTypeId,
			es2.StartRibaStageId,
			es2.EndRibaStageId,
			-1
	FROM	@EnquiryServices	 AS es
	JOIN	SSop.EnquiryServices AS es2 ON (es.GuidValue = es2.Guid);

	DECLARE @ServiceQuoteList AS SCore.ThreeGuidUniqueList,
			@CurrentQuote	  UNIQUEIDENTIFIER,
			@NewQuoteGuid	  UNIQUEIDENTIFIER,
			@MaxQuote		  UNIQUEIDENTIFIER;

	INSERT	@ServiceQuoteList
		 (GuidValue, GuidValueTwo, GuidValueThree)
	SELECT	q.Guid,
			NEWID (),
			es2.GuidValueTwo
	FROM	SSop.Quotes			 AS q
	JOIN	SSop.EnquiryServices AS es ON (es.ID	= q.EnquiryServiceID)
	JOIN	@EnquiryServices	 AS es2 ON (es.Guid = es2.GuidValue);


	INSERT	@NewGuidList
		 (GuidValue)
	SELECT	GuidValueTwo
	FROM	@EnquiryServices;

	EXEC SCore.DataObjectBulkUpsert @GuidList = @NewGuidList,			-- GuidUniqueList
									@SchemeName = N'SSop',				-- nvarchar(255)
									@ObjectName = N'EnquiryServices',	-- nvarchar(255)
									@IsInsert = @IsInsert OUTPUT;		-- bit	

	DELETE	FROM @NewGuidList;

	SELECT	@MaxQuote	  = MAX (tgul.GuidValue),
			@CurrentQuote = '00000000-0000-0000-0000-000000000000'
	FROM	@ServiceQuoteList AS tgul;

	WHILE @CurrentQuote < @MaxQuote
	BEGIN
		SELECT		@CurrentQuote = GuidValue,
					@NewQuoteGuid = GuidValueTwo
		FROM		@ServiceQuoteList
		WHERE		(GuidValue > @CurrentQuote)
		ORDER BY	GuidValue;

		EXEC SSop.QuotesRevise @SourceGuid = @CurrentQuote,	-- uniqueidentifier
								  @TargetGuid = @NewQuoteGuid;	-- uniqueidentifier

		UPDATE	q
		SET		q.EnquiryServiceID = es.ID
		FROM	SSop.Quotes			 AS q
		JOIN	@ServiceQuoteList	 AS ql ON (q.Guid  = ql.GuidValueTwo)
		JOIN	SSop.EnquiryServices AS es ON (es.Guid = ql.GuidValueThree);

	END;


	-- Allocate a new Enquiry number. 

	UPDATE	SSop.Enquiries
	SET		RowStatus = 1
	WHERE	(ID = @ID);
END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[EnquiryService_MergeInfo]
--
GO





CREATE OR ALTER VIEW [SSop].[EnquiryService_MergeInfo]
AS
SELECT		es.ID,
			es.RowStatus,
			es.RowVersion,
			q.Guid,
			e.Guid AS EnquiryGuid,
			q.Guid AS QuoteGuid,
			es.Guid AS ParentGuid
FROM		SSop.EnquiryServices				  AS es
JOIN		SSop.Enquiries AS e ON (e.ID = es.EnquiryId)
JOIN		SSop.EnquiryService_ExtendedInfo AS esei ON (esei.Id = es.ID)
JOIN		SSop.Quotes AS q ON (q.Id = esei.QuoteID)


GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[Enquiry_MergeInfo]
--
GO




CREATE OR ALTER VIEW [SSop].[Enquiry_MergeInfo]
AS
SELECT		e.ID,
			e.RowStatus,
			e.RowVersion,
			e.Guid AS ParentGuid,
			e.Number																					 AS EnquiryNumber,
			e.ProposalLetter,
			e.DescriptionOfWorks,
			e.Date																						 AS EnquiryDate,
																																	/* UPRN */
			uprn.Number																					 AS UPRN,
			uprn.AddressLine1																			 AS PropertyAddressLine1,	-- was PropertyAddress1
			uprn.AddressLine2																			 AS PropertyAddressLine2,	-- was PropertyAddress2
			uprn.AddressLine3																			 AS PropertyAddressLine3,	-- was PropertyAddress3
			uprn.Town																					 AS PropertyTown,
			uprnc.Name																					 AS PropertyCounty,
			uprn.Postcode																				 AS PropertyPostcode,
			uprn.FormattedAddressComma																	 AS PropertyAddress,
			uprn.FormattedAddressCR																		 AS PropertyAddressBlock,
			COALESCE (	 uprn.Name + ' ',
						 ''
					 ) + COALESCE (	  uprn.Number + ' ',
									  ''
								  ) + uprn.AddressLine1													 AS PropertyShortAddress,
																																	/* Client */
			cacc.Name																					 AS ClientName,				-- was [Label] or [Title]
			cacc.CompanyRegistrationNumber																 AS ClientCompanyRegNo,
			cadd.AddressLine1																			 AS ClientAddressLine1,		-- was ClientAddress1
			cadd.AddressLine2																			 AS ClientAddressLine2,		-- was ClientAddress2
			cadd.AddressLine3																			 AS ClientAddressLine3,		-- was ClientAddress3
			cadd.Town																					 AS ClientTown,
			caddc.Name																					 AS ClientCounty,
			cadd.Postcode																				 AS ClientPostcode,
			cadd.FormattedAddressComma																	 AS ClientAddress,			-- was AddressClient
			cadd.FormattedAddressCR																		 AS ClientAddressBlock,
			ccon.DisplayName																			 AS ClientContactName,
			ccon.FirstName																				 AS ClientFirstName,
			ccon.Surname																				 AS ClientSurname,
			ccon.Email																					 AS ClientEmail,
			ccon.Phone																					 AS ClientPhone,
			ccon.Mobile																					 AS ClientMobile,
			aacc.Name																					 AS AgentName,				-- was [Label] or [Title]
			aacc.CompanyRegistrationNumber																 AS AgentCompanyRegNo,
			aadd.AddressLine1																			 AS AgentAddressLine1,		-- was ClientAddress1
			aadd.AddressLine2																			 AS AgentAddressLine2,		-- was ClientAddress2
			aadd.AddressLine3																			 AS AgentAddressLine3,		-- was ClientAddress3
			aadd.Town																					 AS AgentTown,
			aaddc.Name																					 AS AgentCounty,
			aadd.Postcode																				 AS AgentPostcode,
			aadd.FormattedAddressComma																	 AS AgentAddress,			-- was AddressClient
			aadd.FormattedAddressCR																		 AS AgentAddressBlock,
			acon.DisplayName																			 AS AgentContactName,
			acon.FirstName																				 AS AgentFirstName,
			acon.Surname																				 AS AgentSurname,
			acon.Email																					 AS AgentEmail,
			acon.Phone																					 AS AgentPhone,
			acon.Mobile																					 AS AgentMobile,

			facc.Name																					 AS FinanceName,				-- was [Label] or [Title]
			facc.CompanyRegistrationNumber																 AS FinanceCompanyRegNo,
			fadd.AddressLine1																			 AS FinanceAddressLine1,		-- was ClientAddress1
			fadd.AddressLine2																			 AS FinanceAddressLine2,		-- was ClientAddress2
			fadd.AddressLine3																			 AS FinanceAddressLine3,		-- was ClientAddress3
			fadd.Town																					 AS FinanceTown,
			faddc.Name																					 AS FinanceCounty,
			fadd.Postcode																				 AS FinancePostcode,
			fadd.FormattedAddressComma																	 AS FinanceAddress,			-- was AddressClient
			fadd.FormattedAddressCR																		 AS FinanceAddressBlock,
			fcon.DisplayName																			 AS FinanceContactName,
			fcon.FirstName																				 AS FinanceFirstName,
			fcon.Surname																				 AS FinanceSurname,
			fcon.Email																					 AS FinanceEmail,
			fcon.Phone																					 AS FinancePhone,
			fcon.Mobile																					 AS FinanceMobile,

			CASE
				WHEN e.SendInfoToClient = 1 THEN cacc.Name
				ELSE aacc.Name
			END																							 AS RecipientName,			-- was [Label] or [Title]
			CASE
				WHEN e.SendInfoToClient = 1 THEN cacc.CompanyRegistrationNumber
				ELSE aacc.CompanyRegistrationNumber
			END																							 AS RecipientCompanyRegNo,
			CASE
				WHEN e.SendInfoToClient = 1 THEN cadd.AddressLine1
				ELSE aadd.AddressLine1
			END																							 AS RecipientAddressLine1,	-- was ClientAddress1
			CASE
				WHEN e.SendInfoToClient = 1 THEN cadd.AddressLine2
				ELSE aadd.AddressLine2
			END																							 AS RecipientAddressLine2,	-- was ClientAddress2
			CASE
				WHEN e.SendInfoToClient = 1 THEN cadd.AddressLine3
				ELSE aadd.AddressLine3
			END																							 AS RecipientAddressLine3,	-- was ClientAddress3
			CASE
				WHEN e.SendInfoToClient = 1 THEN cadd.Town
				ELSE aadd.Town
			END																							 AS RecipientTown,
			CASE
				WHEN e.SendInfoToClient = 1 THEN caddc.Name
				ELSE aaddc.Name
			END																							 AS RecipientCounty,
			CASE
				WHEN e.SendInfoToClient = 1 THEN cadd.Postcode
				ELSE aadd.Postcode
			END																							 AS RecipientPostcode,
			CASE
				WHEN e.SendInfoToClient = 1 THEN cadd.FormattedAddressComma
				ELSE aadd.FormattedAddressComma
			END																							 AS RecipientAddress,		-- was AddressClient
			CASE
				WHEN e.SendInfoToClient = 1 THEN cadd.FormattedAddressCR
				ELSE aadd.FormattedAddressCR
			END																							 AS RecipientAddressBlock,
			CASE
				WHEN e.SendInfoToClient = 1 THEN ccon.DisplayName
				ELSE acon.DisplayName
			END																							 AS RecipientContactName,
			CASE
				WHEN e.SendInfoToClient = 1 THEN ccon.FirstName
				ELSE acon.FirstName
			END																							 AS RecipientFirstName,
			CASE
				WHEN e.SendInfoToClient = 1 THEN ccon.Surname
				ELSE ccon.Surname
			END																							 AS RecipientSurname,
			CASE
				WHEN e.SendInfoToClient = 1 THEN ccon.Email
				ELSE ccon.Email
			END																							 AS RecipientEmail,
			CASE
				WHEN e.SendInfoToClient = 1 THEN ccon.Phone
				ELSE ccon.Phone
			END																							 AS RecipientPhone,
			CASE
				WHEN e.SendInfoToClient = 1 THEN ccon.Mobile
				ELSE ccon.Mobile
			END																							 AS RecipientMobile,

																																	/* Company */
			offa.Name																					 AS OfficialName,
			offa.AddressLine1																			 AS OfficialAddressLine1,
			offa.AddressLine2																			 AS OfficialAddressLine2,
			offa.AddressLine3																			 AS OfficialAddressLine3,
			offa.Town																					 AS OfficialTown,
			offac.Name																					 AS OfficialCounty,
			offa.Postcode																				 AS OfficialPostcode,
			offcon.Email																				 AS OfficialEmail,
			offcon.Phone																				 AS OfficialPhone,
			offcon.Mobile																				 AS OfficialMobile,


																																	/* Signatory */
			sigconm.Email																				 AS SignatorytEmail,
			sig.FullName																					 AS SignatoryName,
			sig.FullName + N' ' + COALESCE (	  sigcon.PostNominals,
											  ''
										  )																 AS SignatoryPostNominals,
			sigcon.Initials																				 AS SignatoryInitials,
			sig.JobTitle																					 AS SignatoryJobTitle,
			Disciplines.TotalFee
FROM		SSop.Enquiries				  AS e
JOIN		SCore.OrganisationalUnits AS lead_ou ON (lead_ou.ID = e.OrganisationalUnitID)
LEFT JOIN		SCrm.Contact_MergeInfo	  AS offcon ON (offcon.ID = lead_ou.OfficialContactId)
LEFT JOIN		SCrm.Addresses			  AS offa ON (offa.ID = lead_ou.OfficialAddressId)
JOIN		SCrm.Counties			  AS offac ON (offac.ID = offa.CountyID)
JOIN		SJob.Properties			  AS uprn ON (uprn.ID = e.PropertyId)
JOIN		SCrm.Counties			  AS uprnc ON (uprnc.ID = uprn.CountyId)
JOIN		SCrm.Accounts			  AS cacc ON (cacc.ID = e.ClientAccountId)
JOIN		SCrm.AccountAddresses	  AS caad ON (caad.ID = e.ClientAddressId)
JOIN		SCrm.Addresses			  AS cadd ON (cadd.ID = caad.AddressID)
JOIN		SCrm.AccountContacts	  AS cac ON (cac.ID = e.ClientAccountContactId)
JOIN		SCrm.Contact_MergeInfo	  AS ccon ON (ccon.ID = cac.ContactID)
JOIN		SCrm.Counties			  AS caddc ON (caddc.ID = cadd.CountyID)
JOIN		SCrm.Accounts			  AS aacc ON (aacc.ID = e.AgentAccountId)
JOIN		SCrm.AccountAddresses	  AS aaad ON (aaad.ID = e.AgentAddressId)
JOIN		SCrm.Addresses			  AS aadd ON (aadd.ID = aaad.AddressID)
JOIN		SCrm.AccountContacts	  AS aac ON (aac.ID = e.AgentAccountContactId)
JOIN		SCrm.Contact_MergeInfo	  AS acon ON (acon.ID = aac.ContactID)
JOIN		SCrm.Counties			  AS aaddc ON (aaddc.ID = aadd.CountyID)
JOIN		SCrm.Accounts			  AS facc ON (facc.ID = e.ClientAccountId)
JOIN		SCrm.AccountAddresses	  AS faad ON (faad.ID = e.ClientAddressId)
JOIN		SCrm.Addresses			  AS fadd ON (fadd.ID = caad.AddressID)
JOIN		SCrm.AccountContacts	  AS fac ON (fac.ID = e.ClientAccountContactId)
JOIN		SCrm.Contact_MergeInfo	  AS fcon ON (fcon.ID = cac.ContactID)
JOIN		SCrm.Counties			  AS faddc ON (faddc.ID = cadd.CountyID)
JOIN		SCore.Identities		  AS sig ON (sig.ID = e.SignatoryIdentityId)
LEFT JOIN	SCrm.Contacts			  AS sigcon ON (sigcon.ID = sig.ContactId)
LEFT JOIN	SCrm.Contact_MergeInfo	  AS sigconm ON (sigconm.ID = sigcon.ID)
OUTER APPLY (
	SELECT	SUM(esei.QuoteNet) AS TotalFee
	FROM	SSop.EnquiryServices AS es
	JOIN	SSop.EnquiryService_ExtendedInfo AS esei ON (esei.id = es.id)
	WHERE	(es.RowStatus NOT IN (0, 254))
		AND	(es.EnquiryId = e.ID)
		
) Disciplines 
		
		

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[Quote_JobsSummary]
--
GO


CREATE OR ALTER VIEW [SSop].[Quote_JobsSummary]
AS
SELECT		MIN (qi.ID)							   AS ID,
			q.RowStatus,
			q.Guid								   AS QuoteGuid,
			q.Overview,
			--p.Guid								   AS UprnGuid,
			q.IsSubjectToNDA,
			SUM (qit.LineNet)					   AS Net,
			SUM (	CASE
						WHEN rs.Number = 1 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage1Fee,
			SUM (	CASE
						WHEN rs.Number = 2 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage2Fee,
			SUM (	CASE
						WHEN rs.Number = 3 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage3Fee,
			SUM (	CASE
						WHEN rs.Number = 4 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage4Fee,
			SUM (	CASE
						WHEN rs.Number = 5 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage5Fee,
			SUM (	CASE
						WHEN rs.Number = 6 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage6Fee,
			SUM (	CASE
						WHEN rs.Number = 7 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage7Fee,
			SUM (	CASE
						WHEN rs.Number = 99 THEN qit.LineNet
						ELSE 0
					END
				)								   AS PreConstructionStageFee,
			SUM (	CASE
						WHEN rs.Number = 999 THEN qit.LineNet
						ELSE 0
					END
				)								   AS ConstructionStageFee,
			ou.Guid								   AS OrganisationalUnitGuid,
			jt.Guid								   AS JobTypeGuid,
			--acc.Guid							   AS ClientAccountGuid,
			--ad.Guid								   AS ClientAddressGuid,
			--c.Guid								   AS ClientContactGuid,
			cr.Guid								   AS ContractGuid,
			--agent_acc.Guid						   AS AgentAccountGuid,
			--agent_ad.Guid						   AS AgentAddressGuid,
			--agent_c.Guid						   AS AgentContactGuid,
			'00000000-0000-0000-0000-000000000000' AS IdentityGuid,
			-1									   AS QuoteItemId,
			q.ExternalReference,
			SUM (qit.LineNet)					   AS AgreedFee,
			jt.Name								   AS JobType,
			q.DateAccepted,
			q.FeeCap,
			--proj.Guid							   AS ProjectGuid,
			ISNULL (   crs.Guid,
					   '00000000-0000-0000-0000-000000000000'
				   )							   AS CurrentRibaStageGuid,
			ISNULL (   ars.Guid,
					   '00000000-0000-0000-0000-000000000000'
				   )							   AS AppointedRibaStageGuid,
			q.ValueOfWork
FROM		SSop.QuoteItems			  AS qi
JOIN		SSop.QuoteItemTotals	  AS qit ON (qit.ID				= qi.ID)
JOIN		SJob.RibaStages			  AS rs ON (rs.ID				= qi.ProvideAtStageID)
JOIN		SProd.Products			  AS p2 ON (p2.ID				= qi.ProductId)
JOIN		SJob.JobTypes			  AS jt ON (p2.CreatedJobType	= jt.ID)
JOIN		SSop.Quotes				  AS q ON (q.ID					= qi.QuoteId)
JOIN		SCore.OrganisationalUnits AS ou ON (ou.ID				= q.OrganisationalUnitID)
JOIN		SSop.Contracts			  AS cr ON (cr.ID				= q.ContractID)
JOIN		SSop.EnquiryServices	  AS es ON (es.ID				= q.EnquiryServiceID)
JOIN		SSop.Enquiries			  AS e ON (e.ID					= es.EnquiryId)
JOIN		SJob.RibaStages			  AS crs ON (crs.ID				= e.CurrentProjectRibaStageID)
JOIN		SJob.RibaStages			  AS ars ON (ars.ID				= q.AppointmentFromRibaStageId)
--JOIN		SCrm.Accounts			  AS acc ON (acc.ID				= e.ClientAccountId)
--JOIN		SCrm.AccountAddresses	  AS ad ON (ad.ID				= e.ClientAddressId)
--JOIN		SCrm.AccountContacts	  AS c ON (c.ID					= e.ClientAccountContactId)
--JOIN		SCrm.Accounts			  AS agent_acc ON (agent_acc.ID = e.AgentAccountId)
--JOIN		SCrm.AccountAddresses	  AS agent_ad ON (agent_ad.ID	= e.AgentAddressId)
--JOIN		SCrm.AccountContacts	  AS agent_c ON (agent_c.ID		= e.AgentAccountContactId)
--JOIN		SJob.Properties			  AS p ON (p.ID					= e.PropertyId)
--JOIN		SSop.Projects			  AS proj ON (proj.ID			= e.ProjectId)
WHERE		(qi.RowStatus NOT IN (0, 254))
		AND (qi.Quantity			> 0)
		AND (qi.CreatedJobId		< 0)
		AND (qi.DoNotConsolidateJob = 0)
		AND (NOT EXISTS
	(
		SELECT	1
		FROM	SProd.Products AS prod2
		WHERE	(prod2.NeverConsolidate = 1)
			AND (qi.ProductId			= prod2.ID)
	)
			)
GROUP BY	q.RowStatus,
			q.Guid,
			q.Overview,
			--p.Guid,
			q.IsSubjectToNDA,
			jt.Guid,
			jt.Name,
			ou.Guid,
			--acc.Guid,
			--ad.Guid,
			--c.Guid,
			cr.Guid,
			--agent_acc.Guid,
			--agent_ad.Guid,
			--agent_c.Guid,
			q.ExternalReference,
			q.DateAccepted,
			q.FeeCap,
			--proj.Guid,
			crs.Guid,
			ars.Guid,
			q.ValueOfWork
UNION ALL
SELECT		qi.ID								  AS ID,
			q.RowStatus,
			q.Guid,
			q.Overview,
			--p.Guid,
			q.IsSubjectToNDA,
			qit.LineNet,
			CASE
				WHEN rs.Number = 1 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 2 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 3 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 4 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 5 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 6 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 7 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 99 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 999 THEN qit.LineNet
				ELSE 0
			END,
			ou.Guid,
			jt.Guid,
			--acc.Guid,
			--ad.Guid,
			--c.Guid,
			cr.Guid,
			--agent_acc.Guid,
			--agent_ad.Guid,
			--agent_c.Guid,
			'00000000-0000-0000-0000-000000000000',
			qi.ID,
			q.ExternalReference,
			--vow.Guid,
			qi.Net,
			jt.Name,
			q.DateAccepted,
			q.FeeCap,
			--proj.Guid							  AS ProjectGuid,
			ISNULL (   crs.Guid,
					   '00000000-0000-0000-0000-000000000000'
				   ),
			ISNULL (   ars.Guid,
					   '00000000-0000-0000-0000-000000000000'
				   ),
			q.ValueOfWork
FROM		SSop.QuoteItems			  AS qi
JOIN		SSop.QuoteItemTotals	  AS qit ON (qit.ID				= qi.ID)
JOIN		SJob.RibaStages			  AS rs ON (rs.ID				= qi.ProvideAtStageID)
JOIN		SSop.Quotes				  AS q ON (q.ID					= qi.QuoteId)
JOIN		SProd.Products			  AS prod ON (prod.ID			= qi.ProductId)
JOIN		SJob.JobTypes			  AS jt ON (jt.ID				= prod.CreatedJobType)
JOIN		SCore.OrganisationalUnits AS ou ON (ou.ID				= q.OrganisationalUnitID)
JOIN		SSop.Contracts			  AS cr ON (cr.ID				= q.ContractID)
JOIN		SSop.EnquiryServices	  AS es ON (es.ID				= q.EnquiryServiceID)
JOIN		SSop.Enquiries			  AS e ON (e.ID					= es.EnquiryId)
JOIN		SJob.RibaStages			  AS crs ON (crs.ID				= e.CurrentProjectRibaStageID)
JOIN		SJob.RibaStages			  AS ars ON (ars.ID				= q.AppointmentFromRibaStageId)
--JOIN		SCrm.Accounts			  AS acc ON (acc.ID				= e.ClientAccountId)
--JOIN		SCrm.AccountAddresses	  AS ad ON (ad.ID				= e.ClientAddressId)
--JOIN		SCrm.AccountContacts	  AS c ON (c.ID					= e.ClientAccountContactId)
--JOIN		SCrm.Accounts			  AS agent_acc ON (agent_acc.ID = e.AgentAccountId)
--JOIN		SCrm.AccountAddresses	  AS agent_ad ON (agent_ad.ID	= e.AgentAddressId)
--JOIN		SCrm.AccountContacts	  AS agent_c ON (agent_c.ID		= e.AgentAccountContactId)
--JOIN		SJob.Properties			  AS p ON (p.ID					= e.PropertyId)
--JOIN		SSop.Projects			  AS proj ON (proj.ID			= e.ProjectId)
WHERE		(qi.RowStatus NOT IN (0, 254))
		AND (qi.Quantity			  > 0)
		AND (qi.CreatedJobId		  < 0)
		AND
		  (
			  (prod.NeverConsolidate  = 1)
		   OR (qi.DoNotConsolidateJob = 1)
		  );
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_QuotesDataPills]
--
GO


CREATE OR ALTER FUNCTION [SSop].[tvf_QuotesDataPills]
  (
    @Guid              UNIQUEIDENTIFIER,
    @DateAccepted      DATE,
    @DateRejected      DATE,
	@ProjectGuid		UNIQUEIDENTIFIER
  )
RETURNS @DataPills TABLE
  (
    [ID]        [INT]        IDENTITY (1, 1) NOT NULL,
    [Label]     NVARCHAR(50) NOT NULL,
    [Class]     NVARCHAR(50) NOT NULL,
    [SortOrder] INT          NOT NULL
  )
AS
  BEGIN
	DECLARE	@IsSubjectToNDA BIT 

	SELECT	@IsSubjectToNDA = p.IsSubjectToNDA
	FROM	SSop.Projects AS p
	WHERE	(p.Guid = @ProjectGuid)


    IF (@IsSubjectToNDA = 1)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'NDA',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  1		-- SortOrder - int
                )
      END

    -- Show that the quote is accepted.
    IF (@DateAccepted IS NOT NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Accepted',	-- Label - nvarchar(50)
                  N'bg-success',	-- Class - nvarchar(50)
                  1		-- SortOrder - int
                )
      END

    IF (@DateRejected IS NOT NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Rejected',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  1		-- SortOrder - int
                )
      END

    

    -- Warn if the quote is accepted but jobs haven't been created. 
    IF (@DateAccepted IS NOT NULL)
      BEGIN
        DECLARE @JobCount INT

        SELECT
                @JobCount = COUNT(1)
        FROM
                SSop.Quote_JobsSummary js
        WHERE
                (js.QuoteGuid = @Guid)

        IF (@JobCount > 0)
          BEGIN
            INSERT @DataPills
                  (
                    Label,
                    Class,
                    SortOrder
                  )
            VALUES
                    (
                      CONVERT(NVARCHAR(50), @JobCount) + N' job(s) pending creation.',	-- Label - nvarchar(50)
                      N'bg-warning',	-- Class - nvarchar(50)
                      1		-- SortOrder - int
                    )
          END;
      END

	  --Finance Account On Hold
	  IF (EXISTS
			(
				SELECT 
						AC.AccountStatusID
				FROM 
					SSop.Quotes AS Q
				JOIN
					SSop.Quote_ExtendedInfo AS QE ON (Q.ID = QE.ID)
				JOIN 
					SCrm.Accounts AC ON (QE.FinanceAccountId = AC.ID)
				WHERE Q.Guid = @Guid AND AC.AccountStatusID = 4
			)	
		)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Credit Hold',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  1		-- SortOrder - int
                )
      END;

    RETURN
  END


GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

