CREATE OR ALTER PROCEDURE [SFin].[InvoiceRequestUpsert]
(
    @JobGuid UNIQUEIDENTIFIER,
	@RequesterUserGuid UNIQUEIDENTIFIER,
	@Notes NVARCHAR(MAX),
    @Guid UNIQUEIDENTIFIER
)
AS 
BEGIN 
    DECLARE @JobID INT,
			@RequesterUserId INT,
			@IsInsert BIT

	SELECT  @JobID = ID 
    FROM    SJob.Jobs
    WHERE   ([Guid] = @JobGuid)

	SELECT	@RequesterUserId = ID 
	FROM	SCore.Identities 
	WHERE	(Guid = @RequesterUserGuid)

    EXEC SCore.UpsertDataObject @Guid = @Guid,					-- uniqueidentifier
							@SchemeName = N'SFin',				-- nvarchar(255)
							@ObjectName = N'InvoiceRequests',				-- nvarchar(255)
							@IsInsert = @IsInsert OUTPUT,	-- bit
							@IncludeDefaultSecurity = 0
    IF (@IsInsert = 1)
    BEGIN
		INSERT	SFin.InvoiceRequests
			 (RowStatus, Guid, Notes, RequesterUserId, CreatedDateTimeUTC, JobId)
		VALUES
			 (
				 1,	-- RowStatus - tinyint
				 @Guid,	-- Guid - uniqueidentifier
				 @Notes,	-- Notes - nvarchar(max)
				 @RequesterUserId,	-- RequesterUserId - int
				 GETUTCDATE(),	-- CreatedDateTimeUTC - datetime2(7)
				 @JobID	-- JobId - int
			 )
    END
    ELSE
    BEGIN 
        UPDATE  SFin.InvoiceRequests
		SET		Notes = @Notes,
				@JobID = @JobID
        WHERE   ([Guid] = @Guid)
    END
END
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
