			 (
				 1,	-- RowStatus - tinyint
				 @Guid,	-- Guid - uniqueidentifier
				 @InvoiceRequestID,	-- InvoiceRequestId - int
				 @MilestoneId,	-- MilestoneId - bigint
				 @ActivityId,	-- ActivityId - bigint
				 @Net	-- Net - decimal(19, 2)
