--
-- Create or alter function [SJob].[tvf_JobActivity]
--
GO



CREATE OR ALTER FUNCTION [SJob].[tvf_JobActivity] 
(
    @UserId INT,
    @ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
            --WITH SCHEMABINDING
AS
RETURN 
SELECT  a.ID,
        a.RowStatus, 
        a.RowVersion,
        a.Guid,
        a.Title,
        a.[Date] AS [Start],
        a.EndDate AS [End],
        s.Name AS [Status],
        t.Name AS [Type],
		i.Guid SurveyorGuid,
		i.FullName AS SurveyorName,
		ActionCount.Total AS TotalActions,
		ISNULL(ActionCount.Outstanding, 0) AS OutstandingActions,
		CONVERT(NVARCHAR(30), ActionCount.Total) + N' | ' + CONVERT(NVARCHAR(30), ISNULL(ActionCount.Outstanding, 0)) AS Actions,
		CONVERT(NVARCHAR(20), CASE WHEN (EXISTS (SELECT 1 FROM SFin.InvoiceRequestItems iri WHERE (iri.ActivityId = a.ID) AND (iri.RowStatus NOT IN (0, 254)))) THEN 1 ELSE 0 END) + N' | '
		+ CONVERT(NVARCHAR(20), CASE WHEN (EXISTS (SELECT 1 FROM SFin.TransactionDetails td WHERE (td.ActivityId = a.ID) AND (td.RowStatus NOT IN (0, 254)))) THEN 1 ELSE 0 END) AS RequestedInvoiced,
		j.FinanceAccountID, -- NEW [CBLD-535]
		CASE
			WHEN t.IsBillable = 0 THEN 'No' ELSE 'Yes' -- [CBLD-534] => Checking if an activity isbi
		END AS IsBillable
FROM    SJob.Activities a
JOIN	SJob.Jobs AS j ON (a.JobID = j.ID) --NEW [CBLD-535]
JOIN    SJob.ActivityStatus s ON (s.Id = a.ActivityStatusID)
JOIN    SJob.ActivityTypes t ON (t.Id = a.ActivityTypeID)
JOIN    SCore.Identities i ON (a.SurveyorID = i.ID)
OUTER APPLY 
(
	SELECT	COUNT(1) AS Total,
			SUM(CASE WHEN act.IsComplete = 0 THEN 1 ELSE 0 END) AS Outstanding
	FROM	SJob.Actions act
	WHERE	(act.RowStatus NOT IN (0, 254))
		AND	(act.ActivityID = a.ID)
) AS ActionCount
WHERE   (a.RowStatus  NOT IN (0, 254))
    AND	(EXISTS
			(
				SELECT	1
				FROM	SCore.ObjectSecurityForUser_CanRead (a.guid, @UserId) oscr
			)
		)
	AND	(
			(EXISTS
				(
					SELECT	1
					FROM	SJob.Jobs j 
					WHERE	 (j.Guid = @ParentGuid)
						AND	(j.RowStatus NOT IN (0, 254))
						AND (j.Id = a.JobID)
				)
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SFin].[tvf_JobInvoiceRequests]
--
GO




CREATE OR ALTER FUNCTION [SFin].[tvf_JobInvoiceRequests] 
(
	@JobGuid UNIQUEIDENTIFIER,
    @UserId INT
)
RETURNS TABLE
    --WITH SCHEMABINDING
AS
RETURN 
SELECT  ir.ID,
        ir.RowStatus,
        ir.RowVersion,
        ir.Guid,
        ir.Notes,
		ir.CreatedDateTimeUTC,
		i.Guid RequesterUserId,
		j.Guid JobId,
		-- New: Get the status of an invoice request.
		(
			SELECT 
				CASE 
					WHEN EXISTS 
					(
						SELECT
						1
							FROM
									SFin.TransactionDetails td
							INNER JOIN
									SFin.InvoiceRequestItems iri on (iri.Id = td.InvoiceRequestItemId)
							WHERE	
									(iri.InvoiceRequestId = ir.ID) 
					) THEN N'Yes' ELSE N'No'
				END) AS IsProcessed
FROM    SFin.InvoiceRequests ir
JOIN	SJob.Jobs j ON (j.ID = ir.JobId)
JOIN	SCore.Identities i ON (i.ID = ir.RequesterUserId)
WHERE   (ir.RowStatus  NOT IN (0, 254))
	AND	(ir.Id > 0)
	AND	(j.Guid = @JobGuid)
	AND	(EXISTS
			(				
	SELECT
			1
	FROM
			SCore.ObjectSecurityForUser_CanRead(j.Guid, @UserId) oscr
			)
		)
	AND	(EXISTS
			(				
	SELECT
			1
	FROM
			SCore.ObjectSecurityForUser_CanRead(ir.Guid, @UserId) oscr
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SFin].[tvf_InvoiceRequests]
--
GO



CREATE OR ALTER FUNCTION [SFin].[tvf_InvoiceRequests] 
(
    @UserId INT
)
RETURNS TABLE
       --WITH SCHEMABINDING
AS
RETURN 
SELECT  ir.ID,
        ir.RowStatus,
        ir.RowVersion,
        ir.Guid,
        ir.Notes,
		ir.CreatedDateTimeUTC,
		i.Guid RequesterUserId,
		i.FullName SurveyorName,
		j.Guid JobId,
		j.Number,
		j.FinanceAccountID,
		-- [CBLD-522]
		STRING_AGG(ActT.Name,', ') ActivityID,							-- Activity name
		-- [CBLD-525]
		Acc.Name ClientName,											-- Client the request is associated with
		MAX(IRI.Net) Net,												-- Invoice Request Amount
		MAX(Act.EndDate) EndDate,												-- On or prior to today's date
		 COALESCE(
        MAX(NULLIF(Acc.BillingInstruction, '')), 
        MAX(NULLIF(j.BillingInstruction, ''))
    ) AS BillingInstruction, -- Picks Account BillingInstruction if available, otherwise Job’s
    CASE 
        WHEN MAX(CASE WHEN ActT.IsBillable = 0 THEN 'No' ELSE 'Yes' END) = 'Yes' 
        THEN 'Yes' ELSE 'No' 
    END AS IsBillable
FROM    SFin.InvoiceRequests ir
JOIN	SJob.Jobs j ON (j.ID = ir.JobId)
JOIN	SCore.Identities i ON (i.ID = ir.RequesterUserId)
INNER JOIN SFin.InvoiceRequestItems AS IRI ON (IRI.InvoiceRequestId = ir.ID)	-- NEW => [CBLD-522]
INNER JOIN SJob.Activities AS Act ON (IRI.ActivityId = Act.ID)					-- NEW => [CBLD-522]
INNER JOIN SJob.ActivityTypes AS ActT ON (Act.ActivityTypeID = ActT.ID)			-- NEW => [CBLD-522]
INNER JOIN SCrm.Accounts AS Acc ON (Acc.ID = j.ClientAccountID)					-- NEW => [CBLD-525]
WHERE   (ir.RowStatus  NOT IN (0, 254))
	AND	(ir.Id > 0)
	AND (EXISTS
			(
				SELECT	1
				FROM	SFin.InvoiceRequestItems AS iri
				WHERE	(iri.RowStatus NOT IN (0, 254))
					AND	(iri.InvoiceRequestId = ir.ID)
			)
		)
	-- [CBLD-524] Completed Activity
	AND (EXISTS
				(
					SELECT 1
					FROM SFin.InvoiceRequestItems AS iri
					INNER JOIN SJob.Activities AS act ON (iri.ActivityId = act.ID)
					WHERE (act.ActivityStatusID = 3) AND (iri.InvoiceRequestId = ir.ID) -- Always connect back to main query
				)
		)
	-- [CBLD-524] Activity must have an associated value
	AND (EXISTS
				(
					SELECT 1
					FROM SFin.InvoiceRequestItems AS iri
					WHERE(iri.RowStatus NOT IN (0, 254))  
						AND (iri.Net > 0.00) 
						AND (iri.InvoiceRequestId = ir.ID)  -- Always connect back to main query
				)
		)
	-- [CBLD-524] Activity is on or prior to today's date 
	AND (EXISTS
				(
					SELECT 1
					FROM SFin.InvoiceRequestItems AS iri
					INNER JOIN SJob.Activities AS Act ON (iri.ActivityId = Act.ID)
					WHERE(iri.RowStatus NOT IN (0, 254))  
						AND (CAST(Act.EndDate AS DATE)  <= CAST(GETDATE() AS DATE))
						AND (iri.InvoiceRequestId = ir.ID)  -- Always connect back to main query
				)
		)
	AND	(EXISTS
			(				
	SELECT
			1
	FROM
			SCore.ObjectSecurityForUser_CanRead(j.Guid, 1471) oscr
			)
		)
	AND	(EXISTS
			(				
	SELECT
			1
	FROM
			SCore.ObjectSecurityForUser_CanRead(ir.Guid, 1471) oscr
			)
		)
	AND	(NOT EXISTS
			(
	SELECT
			1
	FROM
			SFin.TransactionDetails td
	INNER JOIN
			SFin.InvoiceRequestItems iri on (iri.Id = td.InvoiceRequestItemId)
	WHERE	
			(iri.InvoiceRequestId = ir.ID) 
			)
		)
	GROUP BY 
			ir.ID, 
			ir.RowStatus, 
			ir.RowVersion, 
			ir.Guid, 
			ir.Notes, 
			ir.CreatedDateTimeUTC,
			i.Guid, 
			i.FullName, 
			j.Guid, 
			j.Number, 
			j.FinanceAccountID, 
			ActT.Name, 
			Acc.Name;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_JobTransactions]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_JobTransactions] 
(
    @UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
    --WITH SCHEMABINDING
AS
RETURN 
SELECT	t.ID,
		t.Guid,
		t.RowStatus,
		t.Number,
		t.Date,
		tc.RealNet,
		tc.RealVat,
		tc.RealGross,
		tc.RealOutstanding,
		tt.Name AS Type,
		i.FullName AS Surveyor,
		t.SageTransactionReference
FROM	SFin.Transactions t
JOIN	SFin.TransactionCalculations tc ON (tc.Id = t.ID)
JOIN	SFin.TransactionTypes tt ON (tt.ID = t.TransactionTypeID)
JOIN	SJob.Jobs j ON (j.Id = t.JobID)
JOIN	SCore.Identities i ON (i.ID = j.SurveyorID)
WHERE	(j.Guid = @ParentGuid)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_Jobs_DataPills]
--
GO


CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_DataPills]
  (
    @Guid                      UNIQUEIDENTIFIER,
    @AppFormReceived           BIT,
    @ClientAppointmentReceived BIT,
    @ClientAccountGuid         UNIQUEIDENTIFIER,
    @AgentAccountGuid          UNIQUEIDENTIFIER,
	@FinanceAccountGuid		   UNIQUEIDENTIFIER, --new 
    @JobCompleted              DATETIME2,
    @JobCancelled              DATETIME2,
    @JobDormant                DATETIME2,
    @JobStarted                DATETIME2
  )
RETURNS @DataPills TABLE
  (
    [ID]        [INT]        IDENTITY (1, 1) NOT NULL,
    [Label]     NVARCHAR(50) NOT NULL,
    [Class]     NVARCHAR(50) NOT NULL,
    [SortOrder] INT          NOT NULL
  )
AS
  BEGIN
    DECLARE @JobID INT

    SELECT
            @JobID = ID
    FROM
            SJob.Jobs
    WHERE
            (Guid = @Guid)

    -- Subject to NDA
    IF (EXISTS
			(
				SELECT	1
				FROM	SJob.JobStatus AS js
				WHERE	(js.ID = @JobID)
					AND	(js.IsSubjectToNDA = 1)
			)	
		)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'NDA',	-- Label - nvarchar(50)
                  N'bg-warning',	-- Class - nvarchar(50)
                  1		-- SortOrder - int
                )
      END

    -- Complete Job
    IF (@JobCompleted IS NOT NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Job Complete',	-- Label - nvarchar(50)
                  N'bg-success',	-- Class - nvarchar(50)
                  2		-- SortOrder - int
                )
      END

    -- Cancelled Job
    IF (@JobCancelled IS NOT NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Job Cancelled',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  2		-- SortOrder - int
                )
      END


    -- Dormant Job
    IF (@JobDormant IS NOT NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Job Dormant',	-- Label - nvarchar(50)
                  N'bg-warning',	-- Class - nvarchar(50)
                  2		-- SortOrder - int
                )
      END

    -- Started Job
    IF (@JobStarted IS NOT NULL)
      AND
      (@JobCompleted IS NULL)
      AND
      (@JobCancelled IS NULL)
      AND
      (@JobDormant IS NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Job Started',	-- Label - nvarchar(50)
                  N'bg-info',	-- Class - nvarchar(50)
                  2		-- SortOrder - int
                )
      END

    -- Client Account on hold
    IF (EXISTS
      (
          SELECT
                  1
          FROM
                  SCrm.Accounts a
          JOIN
                  SCrm.AccountStatus st ON (st.ID = a.AccountStatusID)
          WHERE
                  (a.Guid = @ClientAccountGuid)
                  AND (st.IsHold = 1)
      )
      )
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Client Account Hold',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  3		-- SortOrder - int
                )
      END

    -- Agent account on hold
    IF (EXISTS
      (
          SELECT
                  1
          FROM
                  SCrm.Accounts a
          JOIN
                  SCrm.AccountStatus st ON (st.ID = a.AccountStatusID)
          WHERE
                  (a.Guid = @AgentAccountGuid)
                  AND (st.IsHold = 1)
      )
      )
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Agent Account Hold',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  3		-- SortOrder - int
                )
      END
	  -- Finance Account On Credit Hold
	  IF (EXISTS
			(
				SELECT 
						1
				FROM 
						SCrm.Accounts Ac
				WHERE Ac.Guid = @FinanceAccountGuid AND Ac.AccountStatusID = 4
			)	
		)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Credit Hold',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  1		-- SortOrder - int
                )
      END


    -- Outstanding Fees
    IF (EXISTS
      (
          SELECT
                  1
          FROM
                  SFin.Transactions t
          JOIN
                  SFin.TransactionCalculations tc ON (tc.ID = t.ID)
          JOIN
                  SFin.TransactionTypes tt ON (tt.ID = t.TransactionTypeID)
          WHERE
                  (t.JobID = @JobID)
                  AND (tc.RealOutstanding <> 0)
                  AND (tt.IsBank = 0)
                  AND (tc.DueDate < GETDATE())
      )
      )
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Overdue Invoices',	-- Label - nvarchar(50)
                  N'bg-warning',	-- Class - nvarchar(50)
                  3		-- SortOrder - int
                )
      END


    -- App Form not received
    IF (@AppFormReceived = 0)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'App Form Not Received',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  4		-- SortOrder - int
                )
      END

	  --Outstanding Actions
	  	  IF(EXISTS
		(
			SELECT 
				1
			FROM SJob.Actions AS a
			WHERE a.RowStatus NOT IN (0, 254)
			AND a.ActionStatusId <> 1
			  AND (
					EXISTS (
						SELECT 1
						FROM SJob.Jobs AS j
						WHERE j.Guid = @Guid
						  AND j.ID = a.JobID
			 
					)
				 OR EXISTS (
						SELECT 1
						FROM SJob.Milestones AS m
						JOIN SJob.Jobs AS jm ON (jm.ID = m.JobID)
						WHERE jm.Guid = @Guid
						  AND a.MilestoneID = m.ID
						  AND m.RowStatus NOT IN (0, 254)
					)
				 OR EXISTS (
						SELECT 1
						FROM SJob.Activities AS act
						WHERE a.ActivityID = act.ID
						  AND act.RowStatus NOT IN (0, 254)
						  AND (
								EXISTS (
									SELECT 1
									FROM SJob.Jobs AS jact
									WHERE jact.Guid = @Guid
									  AND jact.ID = act.JobID
								)
							 OR EXISTS (
									SELECT 1
									FROM SJob.Milestones AS am
									JOIN SJob.Jobs AS amj ON (amj.ID = am.JobID)
									WHERE amj.Guid = @Guid
									  AND act.MilestoneID = am.ID
									  AND am.RowStatus NOT IN (0, 254)
								)
							)
					)
	
			)
		)
	  )
	  BEGIN
		INSERT @DataPills
		(Label,
		 Class,
		 SortOrder	
		)
		VALUES
		(
		 N'Outstanding Actions',	-- Label - nvarchar(50)
                  N'bg-warning',	-- Class - nvarchar(50)
                  4		-- SortOrder - int
		)
	  END


    -- No Written Appointment
    /*IF (EXISTS 
  			(
  				SELECT	1
  				FROM	SJob.Milestones m 
  				JOIN	SJob.MilestoneTypes mt ON (mt.ID = m.MilestoneTypeID)
  				WHERE	(m.JobID = @JobID)
  					AND	(mt.Code = N'WAR')
  					AND	(m.CompletedDateTimeUTC IS NULL)
  					AND	(m.IsNotApplicable = 0)
  			)
  		)
  	BEGIN 
  		INSERT @DataPills
  			(
  				Label, Class, SortOrder
  			)
  		VALUES(
  				  N'No Written Appointment',	-- Label - nvarchar(50)
  				  N'bg-danger',	-- Class - nvarchar(50)
  				  5		-- SortOrder - int
  			  )
  	END*/

    IF (@ClientAppointmentReceived = 0)
	AND	(EXISTS 
	(
		SELECT	1 
		FROM	SJob.JobTypes AS jt 
		JOIN	SJob.Jobs AS j ON (j.JobTypeID = jt.ID)
		WHERE (jt.Name IN (N'CDM PD', N'CDM PD (Construction Phase Only)', N'CDM PD (Pre-Construction Phase Only)'))
	)
		)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'No Client Appointment Received',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  5		-- SortOrder - int
                )
      END

    -- F10 Expired
    IF (EXISTS
      (
          SELECT
                  1
          FROM
                  SJob.Milestones m
          JOIN
                  SJob.MilestoneTypes mt ON (mt.ID = m.MilestoneTypeID)
          WHERE
                  (m.JobID = @JobID)
                  AND (mt.Code = N'F10')
                  AND (m.CompletedDateTimeUTC IS NULL)
                  AND (m.IsNotApplicable = 0)
                  AND (
                          (CONVERT(DATE, ISNULL(m.DueDateTimeUTC, GETUTCDATE())) < CONVERT(DATE, GETUTCDATE()))
                          OR (CONVERT(DATE, ISNULL(m.ScheduledDateTimeUTC, GETUTCDATE())) < CONVERT(DATE, GETUTCDATE()))
                  )
      )
      )
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'F10 Expired',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  6		-- SortOrder - int
                )
      END

	  -- MileStones Past Deadline Date
	  IF (EXISTS
			(
				SELECT	1
				FROM	SJob.Milestones m
				WHERE	(m.JobId = @JobID)
					AND	(m.CompletedDateTimeUTC IS NULL)
					AND	(ISNULL(m.DueDateTimeUTC, GETUTCDATE()) < GETUTCDATE())
			)
		)
		BEGIN 
			INSERT @DataPills
					(
						Label,
						Class,
						SortOrder
					)
			VALUES
					(
						N'Overdue Milestones.',	-- Label - nvarchar(50)
						N'bg-warning',	-- Class - nvarchar(50)
						6		-- SortOrder - int
					)
		END


	  -- Incomplete historic activities 
	  IF	(EXISTS
				(
					SELECT	1
					FROM	SJob.Activities a
					WHERE	(a.JobID = @JobID)
						AND	(a.EndDate < GETUTCDATE())
						AND	(EXISTS
								(
									SELECT	1
									FROM	SJob.ActivityStatus ast
									WHERE	(ast.ID = a.ActivityStatusID)
										AND	(ast.IsCompleteStatus = 0) 
								)
							)
				)	
			)
		BEGIN 
			INSERT @DataPills
					(
						Label,
						Class,
						SortOrder
					)
			VALUES
					(
						N'Incomplete Activities.',	-- Label - nvarchar(50)
						N'bg-warning',	-- Class - nvarchar(50)
						6		-- SortOrder - int
					)
		END

    RETURN
  END


GO
