--
-- Create or alter view [SJob].[Job_FeeDrawdown]
--
GO





CREATE OR ALTER VIEW [SJob].[Job_FeeDrawdown] 
	   --WITH SCHEMABINDING
AS SELECT
		j.ID,
		j.RowStatus,
		j.Guid,
		CASE
				WHEN rs.Number = -1 THEN
					N'Fee Cap'
				ELSE
				CONVERT(NVARCHAR(10),
				rs.Number
				)
		END	  AS Stage,
		CASE
				WHEN rs.Number = -1 THEN
					N'Fee Cap'
				ELSE
				rs.Description
		END	  AS StageLabel,
		CASE rs.Number
				WHEN N'0' THEN
					(0 + ISNULL(Amendments.Stage0Change,
					0
					)
					)
				WHEN N'1' THEN
					(j.RibaStage1Fee + ISNULL(Amendments.Stage1Change,
					0
					)
					)
				WHEN N'2' THEN
					(j.RibaStage2Fee + ISNULL(Amendments.Stage2Change,
					0
					)
					)
				WHEN N'3' THEN
					(j.RibaStage3Fee + ISNULL(Amendments.Stage3Change,
					0
					)
					)
				WHEN N'4' THEN
					(j.RibaStage4Fee + ISNULL(Amendments.Stage4Change,
					0
					)
					)
				WHEN N'5' THEN
					(j.RibaStage5Fee + ISNULL(Amendments.Stage5Change,
					0
					)
					)
				WHEN N'6' THEN
					(j.RibaStage6Fee + ISNULL(Amendments.Stage6Change,
					0
					)
					)
				WHEN N'7' THEN
					(j.RibaStage7Fee + ISNULL(Amendments.Stage7Change,
					0
					)
					)
				WHEN N'99' THEN
					(j.PreConstructionStageFee + ISNULL(Amendments.PreConstructionStageChange,
					0
					)
					)
				WHEN N'999' THEN
					(j.ConstructionStageFee + ISNULL(Amendments.ConstructionStageChange,
					0
					)
					)
				ELSE
				(j.FeeCap + ISNULL(Amendments.FeeCapChange,
				0
				)
				)
		END	  AS Agreed,
		SUM(ISNULL(td.Net,
		0
		))	  AS Invoiced,
		CASE rs.Number
				WHEN N'0' THEN
					0
				WHEN N'1' THEN
					j.RibaStage1Fee
				WHEN N'2' THEN
					j.RibaStage2Fee
				WHEN N'3' THEN
					j.RibaStage3Fee
				WHEN N'4' THEN
					j.RibaStage4Fee
				WHEN N'5' THEN
					j.RibaStage5Fee
				WHEN N'6' THEN
					j.RibaStage6Fee
				WHEN N'7' THEN
					j.RibaStage7Fee
				ELSE
				j.FeeCap
		END - SUM(ISNULL(td.Net,
		0
		))	  AS Remaining,

		-- QUOTEDMEETINGS
		-- [ADD CASE STATEMENT HERE]
		CASE 
			WHEN rs.Number = N'0' THEN 
				CASE 
					WHEN (Amendments.Stage0MeetingChange IS NULL OR Amendments.Stage0MeetingChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfMeetings, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage0MeetingChange) AS INT)
				END
			WHEN rs.Number = N'1' THEN 
				CASE 
					WHEN (Amendments.Stage1MeetingChange IS NULL OR Amendments.Stage1MeetingChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfMeetings, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage1MeetingChange) AS INT)
				END
			WHEN rs.Number = N'2' THEN 
				CASE 
					WHEN (Amendments.Stage2MeetingChange IS NULL OR Amendments.Stage2MeetingChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfMeetings, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage2MeetingChange) AS INT)
				END
			WHEN rs.Number = N'3' THEN 
				CASE 
					WHEN (Amendments.Stage3MeetingChange IS NULL OR Amendments.Stage3MeetingChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfMeetings, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage3MeetingChange) AS INT)
				END
			WHEN rs.Number = N'4' THEN 
				CASE 
					WHEN (Amendments.Stage4MeetingChange IS NULL OR Amendments.Stage4MeetingChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfMeetings, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage4MeetingChange) AS INT)
				END

			WHEN rs.Number = N'5' THEN
				CASE 
					WHEN (Amendments.Stage5MeetingChange IS NULL OR Amendments.Stage5MeetingChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfMeetings, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage5MeetingChange) AS INT)
				END
			WHEN rs.Number = N'6' THEN 
				CASE 
					WHEN (Amendments.Stage6MeetingChange IS NULL OR Amendments.Stage6MeetingChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfMeetings, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage6MeetingChange) AS INT)
				END
			WHEN rs.Number = N'7' THEN 
				CASE 
					WHEN (Amendments.Stage7MeetingChange IS NULL OR Amendments.Stage7MeetingChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfMeetings, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage7MeetingChange) AS INT)
				END
			-- PRECONSTRUCTION
			WHEN rs.Number = N'99' THEN 
			    CASE 
					WHEN (Amendments.PreConstructionStageMeetingChange IS NULL OR Amendments.PreConstructionStageMeetingChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfMeetings, 0)) AS INT)
					ELSE CAST(SUM(Amendments.PreConstructionStageMeetingChange) AS INT)
				END
			-- CONSTRUCTION
			WHEN rs.Number = N'999' THEN
				CASE 
					WHEN (Amendments.ConstructionStageMeetingChange IS NULL OR Amendments.ConstructionStageMeetingChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfMeetings, 0)) AS INT)
					ELSE CAST(SUM(Amendments.ConstructionStageMeetingChange) AS INT)
				END
			ELSE SUM(ISNULL(qs.NumberOfMeetings,0))
		END AS QuotedMeetings,

		
		--SUM(ISNULL(qs.NumberOfMeetings,
		--0
		--))	  AS QuotedMeetings,
		ISNULL(Meetings.MeetingTotal,
		0
		)	  AS CompletedMeetings,

		-- QUOTEDSITEVISITS
		-- [ADD CASE STATEMENT HERE]
		CASE 
			WHEN rs.Number = N'0' THEN 
				CASE 
					WHEN (Amendments.Stage0VisitChange IS NULL OR Amendments.Stage0VisitChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfSiteVisits, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage0VisitChange) AS INT)
				END
			WHEN rs.Number = N'1' THEN 
				CASE 
					WHEN (Amendments.Stage1VisitChange IS NULL OR Amendments.Stage1VisitChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfSiteVisits, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage1VisitChange) AS INT)
				END
			WHEN rs.Number = N'2' THEN 
				CASE 
					WHEN (Amendments.Stage2VisitChange IS NULL OR Amendments.Stage2VisitChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfSiteVisits, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage2VisitChange) AS INT)
				END
			WHEN rs.Number = N'3' THEN 
				CASE 
					WHEN (Amendments.Stage3VisitChange IS NULL OR Amendments.Stage3VisitChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfSiteVisits, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage3VisitChange) AS INT)
				END
			WHEN rs.Number = N'4' THEN 
				CASE 
					WHEN (Amendments.Stage4VisitChange IS NULL OR Amendments.Stage4VisitChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfSiteVisits, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage4VisitChange) AS INT)
				END

			WHEN rs.Number = N'5' THEN
				CASE 
					WHEN (Amendments.Stage5VisitChange IS NULL OR Amendments.Stage5VisitChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfSiteVisits, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage5VisitChange) AS INT)
				END
			WHEN rs.Number = N'6' THEN 
				CASE 
					WHEN (Amendments.Stage6VisitChange IS NULL OR Amendments.Stage6VisitChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfSiteVisits, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage6VisitChange) AS INT)
				END
			WHEN rs.Number = N'7' THEN 
				CASE 
					WHEN (Amendments.Stage7VisitChange IS NULL OR Amendments.Stage7VisitChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfSiteVisits, 0)) AS INT)
					ELSE CAST(SUM(Amendments.Stage7VisitChange) AS INT)
				END
			-- PRECONSTRUCTION
			WHEN rs.Number = N'99' THEN 
			    CASE 
					WHEN (Amendments.PreConstructionStageVisitChange IS NULL OR Amendments.PreConstructionStageVisitChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfMeetings, 0)) AS INT)
					ELSE CAST(SUM(Amendments.PreConstructionStageVisitChange) AS INT)
				END
			-- CONSTRUCTION
			WHEN rs.Number = N'999' THEN
				CASE 
					WHEN (Amendments.ConstructionStageVisitChange IS NULL OR Amendments.ConstructionStageVisitChange = 0) THEN CAST(SUM(ISNULL(qs.NumberOfMeetings, 0)) AS INT)
					ELSE CAST(SUM(Amendments.ConstructionStageVisitChange) AS INT)
				END
			ELSE SUM(ISNULL(qs.NumberOfSiteVisits,0))
		END AS QuotedSiteVisits,
		--SUM(ISNULL(qs.NumberOfSiteVisits,
		--0
		--))	  AS QuotedSiteVisits,
		ISNULL(Meetings.SiteVisitTotal,
		0
		)	  AS CompletedSiteVisits,
		j.ID  AS JobId,
		rs.ID AS StageId
FROM
		SJob.Jobs AS j
CROSS JOIN
		SJob.RibaStages AS rs
LEFT JOIN
		SJob.Activities AS a ON (a.RibaStageId = rs.ID)
				AND (a.JobId = j.ID)
				AND	(a.RowStatus NOT IN (0, 254))
OUTER APPLY
		(
			SELECT
					td.Net *
							CASE
									WHEN tt.IsNegated = 1 THEN
										-1
									ELSE
									1
							END AS Net
			FROM
					SFin.TransactionDetails AS td
			JOIN
					SFin.Transactions AS t ON (t.ID = td.TransactionID)
			JOIN
					SFin.TransactionTypes AS tt ON (tt.ID = t.TransactionTypeID)
			WHERE
					(td.ActivityID = a.ID)
					AND (tt.IsBank = 0)
					AND (td.RowStatus NOT IN (0, 254))
					AND (t.RowStatus NOT IN (0, 254))
		) AS td
LEFT JOIN
		SSop.QuoteItems AS qi ON (qi.CreatedJobId = j.ID)
			AND (qi.RowStatus NOT IN (0, 254))
LEFT JOIN
		SSop.QuoteSections AS qs ON (qs.ID = qi.QuoteSectionId)
				AND (qs.RibaStageId = rs.ID)
OUTER APPLY
		(
			SELECT
					SUM(fa.RibaStage0Change)		   AS Stage0Change,
					SUM(fa.RibaStage1Change)		   AS Stage1Change,
					SUM(fa.RibaStage2Change)		   AS Stage2Change,
					SUM(fa.RibaStage3Change)		   AS Stage3Change,
					SUM(fa.RibaStage4Change)		   AS Stage4Change,
					SUM(fa.RibaStage5Change)		   AS Stage5Change,
					SUM(fa.RibaStage6Change)		   AS Stage6Change,
					SUM(fa.RibaStage7Change)		   AS Stage7Change,
					SUM(fa.PreConstructionStageChange) AS PreConstructionStageChange,
					SUM(fa.ConstructionStageChange)	   AS ConstructionStageChange,
					SUM(fa.FeeCapChange)			   AS FeeCapChange,

					SUM(fa.RibaStage0VisitChange)      AS Stage0VisitChange,
					SUM(fa.RibaStage1VisitChange)      AS Stage1VisitChange,
					SUM(fa.RibaStage2VisitChange)      AS Stage2VisitChange,
					SUM(fa.RibaStage3VisitChange)      AS Stage3VisitChange,
					SUM(fa.RibaStage4VisitChange)      AS Stage4VisitChange,
					SUM(fa.RibaStage5VisitChange)      AS Stage5VisitChange,
					SUM(fa.RibaStage6VisitChange)      AS Stage6VisitChange,
					SUM(fa.RibaStage7VisitChange)      AS Stage7VisitChange,

					SUM(fa.RibaStage0MeetingChange)    AS Stage0MeetingChange,
					SUM(fa.RibaStage1MeetingChange)    AS Stage1MeetingChange,
					SUM(fa.RibaStage2MeetingChange)    AS Stage2MeetingChange,
					SUM(fa.RibaStage3MeetingChange)    AS Stage3MeetingChange,
					SUM(fa.RibaStage4MeetingChange)    AS Stage4MeetingChange,
					SUM(fa.RibaStage5MeetingChange)    AS Stage5MeetingChange,
					SUM(fa.RibaStage6MeetingChange)    AS Stage6MeetingChange,
					SUM(fa.RibaStage7MeetingChange)    AS Stage7MeetingChange,

					SUM(fa.PreConstructionStageMeetingChange) 	  AS PreConstructionStageMeetingChange,
					SUM(fa.PreConstructionStageVisitChange)		  AS PreConstructionStageVisitChange,
					SUM(fa.ConstructionStageMeetingChange)		  AS ConstructionStageMeetingChange, 
					SUM(fa.ConstructionStageVisitChange)		  AS ConstructionStageVisitChange
			FROM
					SJob.FeeAmendment AS fa
			WHERE
					(fa.RowStatus NOT IN (0, 254))
					AND (fa.JobId = j.ID)
		) AS Amendments
OUTER APPLY
		(
			SELECT
					SUM(CASE
							WHEN jat.IsMeeting = 1 THEN
								1
							ELSE
							0
					END
					) AS MeetingTotal,
					SUM(CASE
							WHEN jat.IsSiteVisit = 1 THEN
								1
							ELSE
							0
					END
					) AS SiteVisitTotal
			FROM
					SJob.Activities AS ja
			JOIN
					SJob.ActivityTypes AS jat ON (jat.ID = ja.ActivityTypeID)
			JOIN
					SJob.ActivityStatus AS jas ON (jas.ID = ja.ActivityStatusID)
			WHERE
					(ja.JobId = j.ID)
					AND (jas.Name = N'Complete')
					AND (ja.RowStatus NOT IN (0, 254))
					AND (
							(jat.IsMeeting = 1)
							OR (jat.IsSiteVisit = 1)
					)
					AND (ja.RibaStageId = rs.ID)
		) AS Meetings
WHERE
		(rs.ID > 0)
		AND (
				(
						(rs.IsRealStage = 1)
						AND (
								(j.PreConstructionStageFee = 0)
								AND (j.ConstructionStageFee = 0)
						)
				)
				OR (
						(rs.IsRealStage = 0)
						AND (
								(j.PreConstructionStageFee <> 0)
								OR (j.ConstructionStageFee <> 0)
						)
				)
		)
GROUP BY
		rs.Number,
		rs.Description,
		rs.ID,
		j.RibaStage1Fee,
		j.RibaStage2Fee,
		j.RibaStage3Fee,
		j.RibaStage4Fee,
		j.RibaStage5Fee,
		j.RibaStage6Fee,
		j.RibaStage7Fee,
		j.PreConstructionStageFee,
		j.ConstructionStageFee,
		j.FeeCap,
		j.RowStatus,
		j.Guid,
		j.ID,
		Amendments.Stage0Change,
		Amendments.Stage1Change,
		Amendments.Stage2Change,
		Amendments.Stage3Change,
		Amendments.Stage4Change,
		Amendments.Stage5Change,
		Amendments.Stage6Change,
		Amendments.Stage7Change,
		--NEW
		Amendments.Stage0MeetingChange,
		Amendments.Stage1MeetingChange,
		Amendments.Stage2MeetingChange,
		Amendments.Stage3MeetingChange,
		Amendments.Stage4MeetingChange,
		Amendments.Stage5MeetingChange,
		Amendments.Stage6MeetingChange,
		Amendments.Stage7MeetingChange,
		--NEW
		Amendments.Stage0VisitChange,
		Amendments.Stage1VisitChange,
		Amendments.Stage2VisitChange,
		Amendments.Stage3VisitChange,
		Amendments.Stage4VisitChange,
		Amendments.Stage5VisitChange,
		Amendments.Stage6VisitChange,
		Amendments.Stage7VisitChange,


		Amendments.PreConstructionStageChange,
		Amendments.ConstructionStageChange,
		--NEW
		Amendments.PreConstructionStageMeetingChange,
		Amendments.PreConstructionStageVisitChange,
		Amendments.ConstructionStageMeetingChange,
		Amendments.ConstructionStageVisitChange,

		Amendments.FeeCapChange,
		Meetings.MeetingTotal,
		Meetings.SiteVisitTotal
UNION ALL
SELECT
		j.ID,
		j.RowStatus,
		j.Guid,
		N'Total (ex. Fee Cap.)',
		N'Total (ex. Fee Cap.)',
		j.AgreedFee + j.PreConstructionStageFee + j.ConstructionStageFee + j.RibaStage1Fee + j.RibaStage2Fee
		+ j.RibaStage3Fee + j.RibaStage4Fee + j.RibaStage5Fee + j.RibaStage6Fee + j.RibaStage7Fee
		+ ISNULL(Amendments.TotalChange,
		0
		),
		ISNULL(jf.InvoicedValue,
		0
		),
		j.AgreedFee + j.PreConstructionStageFee + j.ConstructionStageFee + j.RibaStage1Fee + j.RibaStage2Fee
		+ j.RibaStage3Fee + j.RibaStage4Fee + j.RibaStage5Fee + j.RibaStage6Fee + j.RibaStage7Fee
		+ ISNULL(Amendments.TotalChange,
		0
		) - ISNULL(jf.InvoicedValue,
		0
		),
		ISNULL(Quoted.Meetings,
		0
		) AS QuotedMeetings,
		ISNULL(Meetings.MeetingTotal,
		0
		) AS CompletedMeetings,
		ISNULL(Quoted.SiteVisits,
		0
		) AS QuotedSiteVisits,
		ISNULL(Meetings.SiteVisitTotal,
		0
		) AS CompletedSiteVisits,
		j.ID,
		-2
FROM
		SJob.Jobs AS j
LEFT JOIN
		SJob.JobFinance AS jf ON (jf.ID = j.ID)
CROSS APPLY
		(
			SELECT
					SUM(fa.RibaStage0Change + fa.RibaStage1Change + fa.RibaStage2Change + fa.RibaStage3Change + fa.RibaStage4Change
					+ fa.RibaStage5Change + fa.RibaStage6Change + fa.RibaStage7Change + fa.PreConstructionStageChange
					+ fa.ConstructionStageChange
					) AS TotalChange
			FROM
					SJob.FeeAmendment AS fa
			WHERE
					(fa.RowStatus NOT IN (0, 254))
					AND (fa.JobId = j.ID)
		) AS Amendments
OUTER APPLY
		(
			SELECT
					SUM(CASE
							WHEN jat.IsMeeting = 1 THEN
								1
							ELSE
							0
					END
					) AS MeetingTotal,
					SUM(CASE
							WHEN jat.IsSiteVisit = 1 THEN
								1
							ELSE
							0
					END
					) AS SiteVisitTotal
			FROM
					SJob.Activities AS ja
			JOIN
					SJob.ActivityTypes AS jat ON (jat.ID = ja.ActivityTypeID)
			JOIN
					SJob.ActivityStatus AS jas ON (jas.ID = ja.ActivityStatusID)
			WHERE
					(ja.JobId = j.ID)
					AND (jas.Name = N'Complete')
					AND (ja.RowStatus NOT IN (0, 254))
					AND (
							(jat.IsMeeting = 1)
							OR (jat.IsSiteVisit = 1)
					)
		) AS Meetings
OUTER APPLY
		(
			SELECT
					SUM(qs.NumberOfMeetings)   Meetings,
					SUM(qs.NumberOfSiteVisits) SiteVisits
			FROM
					SSop.QuoteItems AS qi
			LEFT JOIN
					SSop.QuoteSections AS qs ON (qs.ID = qi.QuoteSectionId)
			WHERE
					(qi.CreatedJobId = j.ID)
		) AS Quoted
UNION ALL
SELECT
		j.ID,
		j.RowStatus,
		j.Guid,
		N'Total (inc. Fee Cap)',
		N'Total (inc. Fee Cap)',
		j.AgreedFee + j.PreConstructionStageFee + j.ConstructionStageFee + j.RibaStage1Fee + j.RibaStage2Fee
		+ j.RibaStage3Fee + j.RibaStage4Fee + j.RibaStage5Fee + j.RibaStage6Fee + j.RibaStage7Fee + j.FeeCap
		+ ISNULL(Amendments.TotalChange,
		0
		),
		ISNULL(jf.InvoicedValue,
		0
		),
		j.AgreedFee + j.PreConstructionStageFee + j.ConstructionStageFee + j.RibaStage1Fee + j.RibaStage2Fee
		+ j.RibaStage3Fee + j.RibaStage4Fee + j.RibaStage5Fee + j.RibaStage6Fee + j.RibaStage7Fee + j.FeeCap
		+ ISNULL(Amendments.TotalChange,
		0
		) - ISNULL(jf.InvoicedValue,
		0
		),
		ISNULL(Quoted.Meetings,
		0
		) AS QuotedMeetings,
		ISNULL(Meetings.MeetingTotal,
		0
		) AS CompletedMeetings,
		ISNULL(Quoted.SiteVisits,
		0
		) AS QuotedSiteVisits,
		ISNULL(Meetings.SiteVisitTotal,
		0
		) AS CompletedSiteVisits,
		j.ID,
		-3
FROM
		SJob.Jobs AS j
LEFT JOIN
		SJob.JobFinance AS jf ON (jf.ID = j.ID)
CROSS APPLY
		(
			SELECT
					SUM(fa.RibaStage0Change + fa.RibaStage1Change + fa.RibaStage2Change + fa.RibaStage3Change + fa.RibaStage4Change
					+ fa.RibaStage5Change + fa.RibaStage6Change + fa.RibaStage7Change + fa.PreConstructionStageChange
					+ fa.ConstructionStageChange + fa.FeeCapChange
					) AS TotalChange
			FROM
					SJob.FeeAmendment AS fa
			WHERE
					(fa.RowStatus NOT IN (0, 254))
					AND (fa.JobId = j.ID)
		) AS Amendments
OUTER APPLY
		(
			SELECT
					SUM(CASE
							WHEN jat.IsMeeting = 1 THEN
								1
							ELSE
							0
					END
					) AS MeetingTotal,
					SUM(CASE
							WHEN jat.IsSiteVisit = 1 THEN
								1
							ELSE
							0
					END
					) AS SiteVisitTotal
			FROM
					SJob.Activities AS ja
			JOIN
					SJob.ActivityTypes AS jat ON (jat.ID = ja.ActivityTypeID)
			JOIN
					SJob.ActivityStatus AS jas ON (jas.ID = ja.ActivityStatusID)
			WHERE
					(ja.JobId = j.ID)
					AND (jas.Name = N'Complete')
					AND (ja.RowStatus NOT IN (0, 254))
					AND (
							(jat.IsMeeting = 1)
							OR (jat.IsSiteVisit = 1)
					)
		) AS Meetings
OUTER APPLY
		(
			SELECT
					SUM(qs.NumberOfMeetings)   Meetings,
					SUM(qs.NumberOfSiteVisits) SiteVisits

			FROM
					SSop.QuoteItems AS qi
			JOIN
					SSop.QuoteSections AS qs ON (qs.ID = qi.QuoteSectionId)
			WHERE
					(qi.CreatedJobId = j.ID)
				AND	(qi.RowStatus NOT IN (0, 254))
		) AS Quoted
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_Jobs_CDM_MyProjects]
--
GO


CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_CDM_MyProjects]
	(
		@UserID INT
	)
RETURNS TABLE
--WITH SCHEMABINDING
AS
RETURN SELECT	
		j.ID																AS ID,
		j.Guid																AS Guid,
		j.RowStatus															AS RowStatus,

																			--[PROJECT]
		ProjectRef.ProjectRef												AS projectRef,						
		client.Name + N' / ' + agent.Name 									AS clientAgent,						
		p.Name + N' / ' + p.FormattedAddressComma							AS propertyName ,					
		CDMRole.jobRole														AS CDMRole,							
		jobstatus.JobStatus													AS jobStatus,						

																			--[FINANCE]
		TotalAgreedFee.Agreed												AS totalAgreed,
		Remaining.Remaining													AS totalRemaining,

																			--[AGREED DELIVERABLES]
		preconmeetings.QuotedMeetings										AS preconMeetings,
		conmeetings.QuotedMeetings											AS conMeetings,
		compliancevisits.compliancevisits									AS complianceVisit,
		HSFile.HSFile														AS hsFile,

																			--[REMAINING DELIVERABLES]
		remainingprecon.remainingPreCon										AS preconMeetingsRemaining,
		remainingconmeetings.reaminingCon									AS conMeetingsRemaining,
		remainingCompVisits.remainingCompVisits								AS compVisitsRemaining,
		HSIssued.HSIssued													AS HSIssued,

																			--[NO HEADER] => [ Client Duties Issued + CDM Strategy Issued]
		clientDutiesIssued.CDIssued											AS clientDutiesIssued,
		CDMStrategyIssued.CDMStratIssued									AS CDMStrategyIssued,

																			--[PCI]
		PCIInspectionCompleted.PCICompleted									AS PCIInspectionCompleted,
		PCIDateCompleted.PCIDate											AS PCIDate,
		--TODO:: PCI VERSION

																			--[RISK]
		DRRLastIssued.DRRLastIssued											AS DRRLastIssued,

																			--[F10]
		F10Applicable.F10Applicable											AS F10Applicable,
		F10IssuedDate.F10Issued												AS F10IssuedDate,
		F10StartDate.F10StartDate											AS F10Start,
		F10WeekDuration.F10WeekDuration										AS F10WeekDuration,
		F10ExpiryDate.F10ExpiryDate											AS F10ExpiryDate,

																			--[CPP]
		CPPDateReceived.CPPDateReceived										AS CPPDateReceived,
		CPPReviewed.CPPReviewed												AS CPPReviewed,			


																			--[PROGRAMME]


																			--[H&S File]
		HSFReviewedDate.HSFReviewedDate										AS HSFReviewed,
		HSFCompletedDate.HSFCompleted										AS HSFCompleted


FROM		SJob.Jobs AS j
JOIN		SJob.JobStatus	AS js ON (js.ID = j.ID)
JOIN		SJob.Properties AS p ON (p.ID = j.UprnID)
JOIN		SJob.JobTypes	AS t ON (t.ID = j.JobTypeID)
JOIN		SCrm.Accounts	AS client ON (client.ID = j.ClientAccountID)
JOIN		SCrm.Accounts	AS agent ON (agent.ID = j.AgentAccountID)
JOIN		SJob.JobStatus  AS jobstatus ON (j.ID = jobstatus.ID)


	OUTER APPLY
	(
		SELECT CASE
			WHEN EXISTS
			(
				SELECT 1
				FROM SSop.Projects AS p
				WHERE p.ID = 59158 AND p.ExternalReference = ''
			)
			THEN j.ProjectId
			ELSE 
				(
					SELECT (j.ProjectId + N' - ' + j.ExternalReference)
				)
			END AS ProjectRef
	) AS ProjectRef																			--Project Reference


	OUTER APPLY 
	(
		SELECT jt.Name AS jobRole
		FROM SJob.JobTypes as jt
		WHERE jt.ID = j.JobTypeID
	) AS CDMRole


		--[FINANCE]
	OUTER APPLY
		(
			SELECT jobfee.Agreed
			FROM SJob.Job_FeeDrawdown AS jobfee
			WHERE jobfee.StageId = -2 AND jobfee.JobId = j.ID
		) AS TotalAgreedFee																		--Total Agreed Fee
	OUTER APPLY
		(
			SELECT jobfee.Remaining
			FROM SJob.Job_FeeDrawdown AS jobfee
			WHERE jobfee.StageId = -2 AND jobfee.JobId = j.ID
		) AS Remaining																		--Remaining Fee
					
					
		--[AGREED DELIVERABLES]
		OUTER APPLY
		(
			SELECT jobfee.QuotedMeetings
			FROM SJob.Job_FeeDrawdown AS jobfee
			WHERE jobfee.StageId = 10 AND jobfee.JobId = j.ID
		) AS preconmeetings																	--Pre-Con. Meetings
		
		OUTER APPLY
		(
			SELECT jobfee.QuotedMeetings
			FROM SJob.Job_FeeDrawdown AS jobfee
			WHERE jobfee.StageId = 11 AND jobfee.JobId = j.ID
		) AS conmeetings																	--Con. Meetings
		
		OUTER APPLY
		(
			SELECT COUNT(act.ID) AS compliancevisits
			FROM SJob.Activities AS act 
			WHERE act.ActivityTypeID = 23 AND act.JobID = j.ID 
		) AS compliancevisits																--Compliance Visits
		
		OUTER APPLY
		(
			SELECT CASE
				WHEN EXISTS
				(
					SELECT 1 FROM Sjob.Milestones AS m
					WHERE m.MilestoneTypeID = 8 AND m.JobID = j.ID
				) 
			THEN N'Yes'
			ELSE N'No'
			END AS HSFile
		) AS HSFile																			--H&S File (Yes/No)
		

		--[REMAINING DELIVERABLES]
		OUTER APPLY
		(
			SELECT (jobfee.QuotedMeetings - jobfee.CompletedMeetings) AS remainingPreCon
			FROM SJob.Job_FeeDrawdown AS jobfee
			WHERE jobfee.StageId = 10 AND jobfee.JobId = j.ID
		) AS remainingprecon																	--Pre-con Mtgs remaining.

		OUTER APPLY
		(
			
			SELECT (jobfee.QuotedMeetings - jobfee.CompletedMeetings) as reaminingCon
			FROM SJob.Job_FeeDrawdown AS jobfee
			WHERE jobfee.StageId = 11 AND jobfee.JobId = j.ID
	
		) AS remainingconmeetings																--Con Mtgs remaining.

		OUTER APPLY
		(
			SELECT 
				(COUNT(Act.ID) - 
					(SELECT COUNT(Act.ID) -- use primary key
					 FROM SJob.Activities AS Act 
					 WHERE Act.ActivityTypeID = 23 
					   AND Act.JobID = j.ID 
					   AND Act.ActivityStatusID = 3)
				) AS remainingCompVisits
			FROM SJob.Activities AS Act 
			WHERE Act.ActivityTypeID = 23 
			  AND Act.JobID = j.ID

		) AS remainingCompVisits																--Compliance visits

		OUTER APPLY 
		(
			SELECT CASE
			WHEN EXISTS
			(
				SELECT 1
				FROM SJob.Milestones AS bool
				WHERE JobID = j.ID AND MilestoneTypeID = 8 AND IsComplete = 1
			)
			THEN N'Yes'
			ELSE N'No'
			END AS HSIssued																		--H&S Issued

		) AS HSIssued

		OUTER APPLY 
		(
			SELECT CASE 
			WHEN EXISTS
			(
				SELECT 1 
				FROM Sjob.Milestones AS m
				WHERE m.MilestoneTypeID = 2 AND m.IsComplete = 1  AND m.JobID = j.ID
			)
			THEN N'Yes'
			ELSE N'No'
			END AS CDIssued
		) AS clientDutiesIssued																	--Client Duties Issued

		OUTER APPLY 
		(
			SELECT CASE 
			WHEN EXISTS
			(
				SELECT 1 
				FROM Sjob.Milestones AS m
				WHERE m.MilestoneTypeID = 1 AND m.IsComplete = 1  AND m.JobID = j.ID
			)
			THEN N'Yes'
			ELSE N'No'
			END AS CDMStratIssued
		) AS CDMStrategyIssued																	--CDM Strategy Issued

		OUTER APPLY
		(
			SELECT CASE 
			WHEN EXISTS
			(
				SELECT 1 
				FROM Sjob.Milestones AS m
				WHERE m.MilestoneTypeID = 11 AND m.IsComplete = 1  AND m.JobID = j.ID
			)
			THEN N'Yes'
			ELSE N'No'
			END AS PCICompleted
		) AS PCIInspectionCompleted																		-- PCI Inspection Completed

		OUTER APPLY
		(
			SELECT CASE 
			WHEN EXISTS
			(
				SELECT 1
				FROM Sjob.Milestones AS m
				WHERE m.MilestoneTypeID = 11 AND m.IsComplete = 1  AND m.JobID = j.ID
			)
			THEN (SELECT CAST(m.CompletedDateTimeUTC AS DATE) FROM Sjob.Milestones AS m WHERE m.MilestoneTypeID = 11 AND m.JobID = j.ID)
			ELSE NULL
			END AS PCIDate
		) AS PCIDateCompleted																			-- PCI/PDI Date


		--OUTER APPLY 
		--(
		
		--) AS PCIVersion																				--PCI Version ============ TODOD!!!! ============

		OUTER APPLY 
		(
			SELECT CASE
			WHEN EXISTS
			(
				SELECT 1 
				FROM SJob.Activities AS act
				WHERE act.JobID = j.ID AND act.ActivityTypeID = 26 AND act.ActivityStatusID = 3
			)
			THEN (SELECT CAST(act.EndDate AS DATE) FROM Sjob.Activities AS act WHERE act.JobID = j.ID AND act.ActivityTypeID = 26 AND act.ActivityStatusID = 3) 
			ELSE NULL 
			END AS DRRLastIssued
		) AS DRRLastIssued																				--DRR Last Issued


		OUTER APPLY
		(
			SELECT CASE 
				WHEN EXISTS
				(
					SELECT 1 FROM SJob.Milestones WHERE JobID = j.ID AND MilestoneTypeID = 7
				)
				THEN N'Yes'
				ELSE N'No'
			END AS F10Applicable
		) AS F10Applicable																				--F10 Applicable

		OUTER APPLY
		(
			SELECT CASE
			WHEN EXISTS
				(
					SELECT 1 FROM SJob.Milestones WHERE JobID = j.ID AND MilestoneTypeID = 7
				)
				THEN 
				(
					SELECT CAST(CAST(m.CompletedDateTimeUTC AS DATE) AS VARCHAR)
					FROM SJob.Milestones AS m
					WHERE m.MilestoneTypeID = 7 AND JobID = j.ID
				)
				ELSE N'#808080' -- return grey hex 
			END AS F10Issued
		) AS F10IssuedDate																				--F10 Issued Date

		OUTER APPLY 
		(
			SELECT CASE
				WHEN EXISTS
					(
						SELECT 1 FROM SJob.Milestones WHERE JobID = j.ID AND MilestoneTypeID = 7
					)
					THEN 
					(
						SELECT CAST(CAST(m.StartDateTimeUTC AS DATE) AS VARCHAR)
						FROM SJob.Milestones AS m
						WHERE m.MilestoneTypeID = 7 AND JobID = j.ID
					)
					ELSE N'#808080'
			END AS F10StartDate
		) AS F10StartDate																			--F10 Start Date

		OUTER APPLY 
		(
			SELECT CASE
				WHEN EXISTS
					(
						SELECT 1 FROM SJob.Milestones WHERE JobID = j.ID AND MilestoneTypeID = 7
					)
					THEN 
					(
						SELECT CAST(DATEDIFF(WEEK, CAST(m.StartDateTimeUTC AS DATE), CAST(m.DueDateTimeUTC AS DATE)) AS VARCHAR) 
						FROM SJob.Milestones AS m
						WHERE m.MilestoneTypeID = 7 AND JobID = j.ID
					)
					ELSE N'#808080'
				END AS F10WeekDuration
		) AS F10WeekDuration																		--F10 Duration (wks)

		OUTER APPLY 
		(
			SELECT CASE
				WHEN EXISTS
					(
						SELECT 1 FROM SJob.Milestones WHERE JobID = j.ID AND MilestoneTypeID = 7
					)
					THEN 
					(
						SELECT CAST(CAST(m.SubmissionExpiryDate AS DATE) AS VARCHAR)
						FROM SJob.Milestones AS m
						WHERE m.MilestoneTypeID = 7 AND JobID = j.ID
					)
					ELSE N'#808080'
			END AS F10ExpiryDate
		) AS F10ExpiryDate																			--F10 Expiry Date

		OUTER APPLY
		(
			SELECT CASE
					WHEN EXISTS
						(
							SELECT 1 FROM SJob.Milestones WHERE JobID = j.ID AND MilestoneTypeID = 19
						)
						THEN 
						(
							SELECT CAST(m.CompletedDateTimeUTC AS DATE)
							FROM SJob.Milestones AS m
							WHERE m.MilestoneTypeID = 19 AND JobID = j.ID
						)
						ELSE NULL
				END AS CPPDateReceived
		) AS CPPDateReceived																		-- CPP Date / Received	

		OUTER APPLY
		(
			SELECT CASE
				WHEN EXISTS
					(
						SELECT 1 FROM SJob.Milestones WHERE JobID = j.ID AND MilestoneTypeID = 17
					)
					THEN 
					(
						SELECT CAST(m.CompletedDateTimeUTC AS DATE)
						FROM SJob.Milestones AS m
						WHERE m.MilestoneTypeID = 17 AND JobID = j.ID
					)
					ELSE NULL
			END AS CPPReviewed
		) AS CPPReviewed																			-- CPP Reviewed 

		--OUTER APPLY
		--(
		
		--) AS ConstructionStartDate																-- Construction Start Date =======> [TODO]

		--OUTER APPLY
		--(
		
		--) AS ConstructionCompletionDate															-- Construction Completion Date =======> [TODO]

		--OUTER APPLY
		--(
		
		--) AS ConstuctionDuration																	-- (Construction) Duration (wks) =======> [TODO]

		OUTER APPLY
		(
			SELECT CAST(m.ReviewedDateTimeUTC AS DATE) AS HSFReviewedDate
			FROM SJob.Milestones as m 
			WHERE m.MilestoneTypeID = 8 AND  m.JobID = j.ID
		) AS HSFReviewedDate																		--HSF Reviewed

		OUTER APPLY
		(
			SELECT CAST(m.CompletedDateTimeUTC AS DATE) AS HSFCompleted
			FROM SJob.Milestones as m 
			WHERE m.MilestoneTypeID = 8 AND  m.JobID = j.ID
		) AS HSFCompletedDate																		--HSF Completed
		
		
WHERE (j.IsActive	  = 1)
		AND (EXISTS
		(
			SELECT	1
			FROM		SCore.ObjectSecurityForUser_CanRead (	j.Guid,
															@UserID
														) AS oscr
		)
			)
		AND (j.RowStatus NOT IN (0, 254))
		AND (j.SurveyorID = @UserID)
		AND (j.ID		  > 0);
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[Activities_DataPills]
--
GO


CREATE OR ALTER FUNCTION [SJob].[Activities_DataPills]
  (
	@SurveyorGuid				UNIQUEIDENTIFIER,
	@BillableHours				DECIMAL(19,2),
	@JobGuid					UNIQUEIDENTIFIER,
	@RibaStageGuid				UNIQUEIDENTIFIER,
	@IsAdditionalWork			BIT,
	@Guid						UNIQUEIDENTIFIER
	
  )
RETURNS @DataPills TABLE
  (
    [ID]        [INT]        IDENTITY (1, 1) NOT NULL,
    [Label]     NVARCHAR(50) NOT NULL,
    [Class]     NVARCHAR(50) NOT NULL,
    [SortOrder] INT          NOT NULL
  )
AS
  BEGIN
    DECLARE @JobID INT,
			@JobUsesTimeSheets BIT,
			@StageInvoiced DECIMAL(19,2) = 0,
			@StageQuoted DECIMAL (19,2) = 0,
			@BillableValue DECIMAL(19,2) = 0,
			@BillableRate DECIMAL(19,2) = 0

	SELECT
			@JobUsesTimeSheets = jt.UseTimeSheets
	FROM
			SJob.JobTypes jt
	WHERE
			(EXISTS
				(
					SELECT
							1
					FROM
							SJob.Jobs j
					WHERE
							(j.JobTypeID = jt.ID)
							AND (j.Guid = @JobGuid)
				)
			)

	
	-- Data pill for billable/non-billable activities.
	IF (EXISTS
			(
				SELECT *
				FROM SJob.Activities AS Act
				JOIN SJob.Jobs AS J ON (Act.JobID = J.ID)
				JOIN SJob.ActivityTypes ActT ON (ActT.ID = Act.ActivityTypeID)
				WHERE J.Guid = @JobGuid AND ActT.IsBillable = 1 AND AcT.Guid = @Guid
			)	
		)
	BEGIN
		INSERT @DataPills
			  (
				Label,
				Class,
				SortOrder
			  )
		VALUES
			  (
				N'Billable Activity',	-- Label - nvarchar(50)
				N'bg-info',	-- Class - nvarchar(50)
				1		-- SortOrder - int
			  )
	END
	ELSE
	BEGIN
		INSERT @DataPills
			  (
				Label,
				Class,
				SortOrder
			  )
		VALUES
			  (
				N'Non-Billable Activity',	-- Label - nvarchar(50)
				N'bg-info',	-- Class - nvarchar(50)
				2		-- SortOrder - int
			  )
	END

	




	IF (@JobUsesTimeSheets = 1)
	BEGIN
		IF (@IsAdditionalWork = 0)
		BEGIN
			SELECT
					@StageInvoiced = jfd.Invoiced,
					@StageQuoted   = jfd.Agreed
			FROM
					SJob.Job_FeeDrawdown jfd
			JOIN
					SJob.Jobs j ON (j.ID = jfd.JobID)
			JOIN
					SJob.RibaStages rs ON (rs.ID = jfd.StageId)
			WHERE
					(j.Guid = @JobGuid)
					AND (rs.Guid = @RibaStageGuid)
		END
		ELSE
		BEGIN
			SELECT
					@StageInvoiced = ISNULL(jfd.Invoiced, 0),
					@StageQuoted   = ISNULL(jfd.Agreed, 0)
			FROM
					SJob.Jobs j
			LEFT JOIN
					SJob.Job_FeeDrawdown jfd ON (j.ID = jfd.JobID)
			WHERE
					(j.Guid = @JobGuid)
					AND (ISNULL(jfd.StageId, -1) = -1)
		END

		SELECT
				@BillableValue = BillableRate * @BillableHours,
				@BillableRate  = BillableRate
		FROM
				SCore.Identities
		WHERE
				(Guid = @SurveyorGuid)

		IF (@BillableRate = 0
			AND
			@BillableHours <> 0)
		BEGIN
			INSERT @DataPills
					(
						Label,
						Class,
						SortOrder
					)
			VALUES
					(
						N'The current assignee has no billable rate. This work will be FoC.',	-- Label - nvarchar(50)
						N'bg-info',	-- Class - nvarchar(50)
						1		-- SortOrder - int
					)
		END

		IF ((@StageInvoiced + @BillableValue) > @StageQuoted)
		BEGIN
			INSERT @DataPills
					(
						Label,
						Class,
						SortOrder
					)
			VALUES
					(
						N'The quoted value for this stage has been exceeded.',	-- Label - nvarchar(50)
						N'bg-danger',	-- Class - nvarchar(50)
						1		-- SortOrder - int
					)
		END

		IF (CASE
					WHEN @StageQuoted > 0 THEN
						(@StageInvoiced / @StageQuoted)
					ELSE
					0
			END > 0.9)
		BEGIN
			INSERT @DataPills
					(
						Label,
						Class,
						SortOrder
					)
			VALUES
					(
						N'Over 90% of the quoted value has been used for this stage.',	-- Label - nvarchar(50)
						N'bg-warning',	-- Class - nvarchar(50)
						1		-- SortOrder - int
					)
		END
	END;

	RETURN
END
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[Project_ExtendedInfo]
--
GO




CREATE OR ALTER VIEW	[SSop].[Project_ExtendedInfo]
    --WITH SCHEMABINDING
AS
SELECT	proj.Id,
		proj.RowStatus,
		proj.RowVersion,
		proj.Guid,
		ISNULL(enq.Count, 0) AS EnquiriesCount,
		ISNULL(quote.Count, 0) AS QuotesCount,
		ISNULL(quote.Total, 0) AS QuotesTotalValue,
		ISNULL(quote.AcceptedTotal, 0) AS AcceptedQuotesTotalValue,
		ISNULL(quote.AcceptedCount, 0) AS AcceptedQuotesCount,
		ISNULL(quote.RejectedTotal, 0) AS RejectedQuotesTotalValue,
		ISNULL(quote.RejectedCount, 0) AS RejectedQuotesCount,
		ISNULL(quote.PendingTotal, 0) AS PendingQuotesTotelValue,
		ISNULL(quote.PendingCount, 0) AS PendingQuotesCount,
		ISNULL(job.Count, 0) AS JobsCount,
		ISNULL(job.AgreedFeesTotal, 0) AS JobsTotalAgreedFeesTotal,
		ISNULL(job.InvoicedFeesTotal, 0) AS JobsTotalInvoicedFeesTotal,
		ISNULL(job.RemainingFeesTotal, 0) AS JobsTotalRemainingFeesTotal,
		ISNULL(job.CompletedCount, 0) AS JobsCompletedCount,
		ISNULL(job.CompletedAgreedFeesTotal, 0) AS JobsCompletedAgreedFeesTotal, 
		ISNULL(job.CompletedInvoicedFeesTotal, 0) AS JobsCompletedInvoicedFeesTotal,
		ISNULL(job.CompletedUnInvoicedFeesTotal, 0) AS JobsCompletedUninvoicesFeesTotal,
		ISNULL(job.ActiveCount, 0) AS JobsActiveCount,
		ISNULL(job.ActiveAgreedFeesTotal, 0) AS JobsActiveAgreedFeesTotal,
		ISNULL(job.ActiveInvoicedFeesTotal, 0) AS JobsActiveInvoicedFeesTotal,
		ISNULL(job.ActiveRemainingFeesTotal, 0) AS JobsActiveRemainingFeesTotal,
		ISNULL(job.CancelledCount, 0) AS JobsCancelledCount,
		ISNULL(job.CancelledAgreedFeesTotal, 0) AS JobsCancelledAgreedFeesTotal,
		ISNULL(job.CancelledInvoicedFeesTotal, 0) AS JobsCancelledInvoicedFeesTotal,
		ISNULL(job.CancelledUnInvoicedFeesTotal, 0) AS JobsCancelledUninvoicedFeesTotal,
		ISNULL(job.PercentageCompleted, 0) AS PercentageCompleted,
		ISNULL(job.PercentageAchievableRevenueAchieved, 0) AS PercentageAchievableRevenueAchieved,
		pl.ListLabel
FROM	SSop.Projects proj
JOIN	SSop.ProjectsList AS pl ON (pl.ID = proj.ID)
OUTER APPLY 
(
	SELECT	COUNT(1) AS [Count]
	FROM	SSop.Enquiries e
	WHERE	(e.ProjectId = proj.ID)
		AND	(e.ProjectId > 0)
) AS enq
OUTER APPLY 
(
	SELECT	COUNT(1) AS [Count],
			SUM(qstt.Net) AS Total,
			SUM(CASE WHEN q.DateAccepted IS NOT NULL THEN qstt.Net ELSE 0 END) AS AcceptedTotal,
			SUM(CASE WHEN q.DateAccepted IS NOT NULL THEN 1 ELSE 0 END) AS AcceptedCount,
			SUM(CASE WHEN q.DateRejected IS NOT NULL THEN qstt.Net ELSE 0 END) AS RejectedTotal,
			SUM(CASE WHEN q.DateRejected IS NOT NULL THEN 1 ELSE 0 END) AS RejectedCount,
			SUM(CASE WHEN q.DateSent IS NOT NULL AND q.DateAccepted IS NULL AND q.DateRejected IS NULL THEN qstt.Net ELSE 0 END) AS PendingTotal,
			SUM(CASE WHEN q.DateSent IS NOT NULL AND q.DateAccepted IS NULL AND q.DateRejected IS NULL THEN 1 ELSE 0 END) AS PendingCount
	FROM	SSop.Quotes q
	OUTER APPLY
	(
		SELECT	SUM(qst.Net) AS Net
		FROM	SSop.QuoteSections qs  
		JOIN	SSop.QuoteSectionTotals qst ON (qst.ID = qs.ID)
		WHERE	(qs.QuoteId = q.ID)
			AND	(qs.RowStatus NOT IN (0, 254))
	) qstt
	WHERE	(q.ProjectId = proj.ID)
		AND	(q.ProjectId > 0)
		AND	(q.RowStatus NOT IN (0, 254))
		
	GROUP BY	q.ProjectId
) AS quote
OUTER APPLY 
(
	SELECT	COUNT(1) AS [Count],
			SUM(fees.Agreed) AS AgreedFeesTotal,
			SUM(fees.Invoiced) AS InvoicedFeesTotal,
			SUM(fees.Remaining) AS RemainingFeesTotal,
			SUM(CASE WHEN j.IsComplete = 1 THEN 1 ELSE 0 END) AS CompletedCount,
			SUM(CASE WHEN j.IsComplete = 1 THEN fees.Agreed ELSE 0 END) AS CompletedAgreedFeesTotal,
			SUM(CASE WHEN j.IsComplete = 1 THEN fees.Invoiced ELSE 0 END) AS CompletedInvoicedFeesTotal,
			SUM(CASE WHEN j.IsComplete = 1 THEN fees.Remaining ELSE 0 END) AS CompletedUnInvoicedFeesTotal,
			SUM(CASE WHEN j.IsActive = 1 THEN 1 ELSE 0 END) AS ActiveCount,
			SUM(CASE WHEN j.IsActive = 1 THEN fees.Agreed ELSE 0 END) AS ActiveAgreedFeesTotal,
			SUM(CASE WHEN j.IsActive = 1 THEN fees.Invoiced ELSE 0 END) AS ActiveInvoicedFeesTotal,
			SUM(CASE WHEN j.IsActive = 1 THEN fees.Remaining ELSE 0 END) AS ActiveRemainingFeesTotal,
			SUM(CASE WHEN j.IsCancelled = 1 THEN 1 ELSE 0 END) AS CancelledCount,
			SUM(CASE WHEN j.IsCancelled = 1 THEN fees.Agreed ELSE 0 END) AS CancelledAgreedFeesTotal,
			SUM(CASE WHEN j.IsCancelled = 1 THEN fees.Invoiced ELSE 0 END) AS CancelledInvoicedFeesTotal,
			SUM(CASE WHEN j.IsCancelled = 1 THEN fees.Remaining ELSE 0 END) AS CancelledUnInvoicedFeesTotal,
			CASE WHEN (SUM(CASE WHEN j.IsCancelled = 0 THEN 1 ELSE 0 END) > 0) THEN   SUM(CASE WHEN j.IsComplete = 1 THEN 1 ELSE 0 END) / SUM(CASE WHEN j.IsCancelled = 0 THEN 1 ELSE 0 END) * 100 ELSE 0 END AS PercentageCompleted,
			CASE WHEN SUM(fees.Agreed) > 0 THEN (SUM(fees.Invoiced) / (SUM(CASE WHEN j.IsCancelled = 0 THEN fees.Agreed ELSE 0 END) + SUM(CASE WHEN j.IsCancelled = 0 THEN fees.Invoiced ELSE 0 END))) * 100 ELSE 0 END AS PercentageAchievableRevenueAchieved
	FROM	SJob.Jobs j
	OUTER APPLY	
	(
		SELECT	jfd.Agreed,
				jfd.Invoiced, 
				jfd.Remaining
		FROM	SJob.Job_FeeDrawdown jfd 
		WHERE	(j.id = jfd.ID)
			AND	(jfd.Stage = N'Total (ex. Fee Cap.)')
	) AS fees
	WHERE	(j.ProjectId = proj.ID)
		AND	(j.ProjectId > 0)
		AND	(j.RowStatus NOT IN (0, 254))
	GROUP BY	j.ProjectId
) AS job

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SCrm].[MergeAccounts]
--
GO
CREATE OR ALTER PROCEDURE [SCrm].[MergeAccounts]
(
	@FromAccountGuid UNIQUEIDENTIFIER,
	@ToAccountGuid UNIQUEIDENTIFIER
)
AS
BEGIN 
	DECLARE	@FromAccountID INT,
			@ToAccountID INT

	SELECT	@FromAccountID = ID
	FROM	SCrm.Accounts
	WHERE	(guid = @FromAccountGuid)

	SELECT	@ToAccountID = ID 
	FROM	SCrm.Accounts
	WHERE	(Guid = @ToAccountGuid)

	UPDATE	SJob.Jobs
	SET		ClientAccountID = @ToAccountID
	WHERE	(ClientAccountID = @FromAccountID)

	UPDATE	SJob.Jobs
	SET		AgentAccountID = @ToAccountID
	WHERE	(AgentAccountID = @FromAccountID)

	UPDATE	SJob.Jobs
	SET		FinanceAccountID = @ToAccountID
	WHERE	(FinanceAccountID = @FromAccountID)

	UPDATE	SFin.Transactions 
	SET		AccountID = @ToAccountID
	WHERE	(AccountID = @FromAccountID)

	UPDATE	SSop.Enquiries 
	SET		ClientAccountId = @ToAccountID
	WHERE	(ClientAccountId = @FromAccountID)

	UPDATE	SSop.Enquiries 
	SET		AgentAccountId = @ToAccountID
	WHERE	(AgentAccountId = @FromAccountID)

	UPDATE	SSop.Enquiries 
	SET		FinanceAccountID = @ToAccountID
	WHERE	(FinanceAccountID = @FromAccountID)

	UPDATE	aa
	SET		AccountID = @ToAccountID
	FROM	SCrm.AccountAddresses aa
	WHERE	(aa.AccountID = @FromAccountID)
		AND	(NOT EXISTS
				(
					SELECT	1
					FROM	SCrm.AccountAddresses aa2
					WHERE	(aa.AccountID = @ToAccountID)
						AND	(aa2.AddressID = aa.AddressID)
				)
			)

	UPDATE	ac
	SET		AccountID = @ToAccountID
	FROM	SCrm.AccountContacts ac
	WHERE	(ac.AccountID = @FromAccountID)
		AND	(NOT EXISTS
				(
					SELECT	1
					FROM	SCrm.AccountContacts ac2
					WHERE	(ac.AccountID = @ToAccountID)
						AND	(ac2.ContactID = ac.ContactID)
				)
			)

	UPDATE	SCrm.AccountMemos 
	SET		AccountID = @ToAccountID
	WHERE	(AccountID = @FromAccountID)

	/*UPDATE SCrm.AccountProjectDirectoryRoles 
	SET		AccountID = @ToAccountID
	WHERE	(AccountID = @FromAccountID)*/

	UPDATE SJob.ProjectDirectory
	SET		AccountID = @ToAccountID 
	WHERE	(AccountID = @FromAccountID)

	UPDATE	SFin.FinanceMemo
	SET		AccountID = @ToAccountID
	WHERE	(AccountID = @FromAccountID)

	UPDATE	SCrm.Accounts
	SET		RowStatus = 254
	WHERE	(ID = @FromAccountID)
		
END
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [dbo].[Searchinall]
--
GO

CREATE OR ALTER PROCEDURE [dbo].[Searchinall]       
(@strFind AS VARCHAR(MAX))
AS
BEGIN
    SET NOCOUNT ON; 
    --TO FIND STRING IN ALL PROCEDURES        
    BEGIN
        SELECT OBJECT_NAME(OBJECT_ID) SP_Name
              ,OBJECT_DEFINITION(OBJECT_ID) SP_Definition
        FROM   sys.procedures
        WHERE  OBJECT_DEFINITION(OBJECT_ID) LIKE '%'+@strFind+'%'
    END 

    --TO FIND STRING IN ALL VIEWS        
    BEGIN
        SELECT OBJECT_NAME(OBJECT_ID) View_Name
              ,OBJECT_DEFINITION(OBJECT_ID) View_Definition
        FROM   sys.views
        WHERE  OBJECT_DEFINITION(OBJECT_ID) LIKE '%'+@strFind+'%'
    END 

    --TO FIND STRING IN ALL FUNCTION        
    BEGIN
        SELECT ROUTINE_NAME           Function_Name
              ,ROUTINE_DEFINITION     Function_definition
        FROM   INFORMATION_SCHEMA.ROUTINES
        WHERE  ROUTINE_DEFINITION LIKE '%'+@strFind+'%'
               AND ROUTINE_TYPE = 'FUNCTION'
        ORDER BY
               ROUTINE_NAME
    END

    --TO FIND STRING IN ALL TABLES OF DATABASE.    
    BEGIN
        SELECT t.name      AS Table_Name
              ,c.name      AS COLUMN_NAME
        FROM   sys.tables  AS t
               INNER JOIN sys.columns c
                    ON  t.OBJECT_ID = c.OBJECT_ID
        WHERE  c.name LIKE '%'+@strFind+'%'
        ORDER BY
               Table_Name
    END
END
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Commit Transaction
--
IF @@TRANCOUNT>0 COMMIT TRANSACTION
GO



--
-- Set NOEXEC to off
--
SET NOEXEC OFF
GO